// --- FIX CORS: Cấu hình chi tiết & Mạnh mẽ ---
const allowedOrigins = [
    'https://geo.gisvn.space', 
    'https://www.geo.gisvn.space', 
    'https://apigeo.gisvn.space', 
    'http://localhost:3003',
    'http://localhost:5173',
    'http://127.0.0.1:3003',
    'http://127.0.0.1:5173'
];

const corsOptions = {
    origin: function (origin, callback) {
        // Cho phép request không có origin (như curl, mobile app, server-to-server)
        if (!origin) return callback(null, true);

        if (allowedOrigins.indexOf(origin) !== -1) {
            callback(null, true);
        } else {
            // FIX: Tạm thời cho phép tất cả để đảm bảo hệ thống chạy, 
            // Browser sẽ chặn nếu server không trả về header 'Access-Control-Allow-Origin' đúng với Origin gửi lên.
            // Khi dùng callback(null, true), thư viện cors sẽ phản hồi lại đúng Origin đó.
            callback(null, true);
        }
    },
    credentials: true, // Cho phép gửi cookie/auth headers
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS', 'PATCH'],
    allowedHeaders: ['Content-Type', 'Authorization', 'x-user-id', 'x-user-name', 'x-branch-id', 'X-Requested-With', 'Accept', 'Origin'],
    exposedHeaders: ['Content-Range', 'X-Content-Range'],
    optionsSuccessStatus: 200 // Một số trình duyệt cũ/TV yêu cầu 200 thay vì 204
};

app.use(cors(corsOptions));
// Quan trọng: Enable pre-flight (OPTIONS) cho tất cả các routes

app.use(express.json());

// Cấu hình Multer lưu file vào bộ nhớ (RAM) để xử lý nhanh
const upload = multer({ storage: multer.memoryStorage() });

