                            {activeTab === 'LOGS' && <><Activity className="text-orange-500" /> Nhật ký Hệ thống</>}
                            {activeTab === 'SETTINGS' && <><Settings className="text-blue-500" /> Thiết lập Hệ thống</>}
                            {activeTab === 'DATA_LAYERS' && <><Layers className="text-purple-500" /> Quản lý Nguồn Dữ liệu</>}
                        </h2>
                    </div>
                    {renderDbStatus()}
                </div>

                <div className="flex-1 overflow-auto bg-gray-900 relative custom-scrollbar">
                    {activeTab === 'PARCEL_MANAGER' ? (
                        <ParcelManager />
