                                    <input className="w-full bg-gray-900 border border-gray-600 rounded p-3 text-white focus:border-blue-500 outline-none font-mono" placeholder="Tên bảng (VD: huyen_phu_giao)" value={formData.tableName||''} onChange={e=>setFormData({...formData, tableName: e.target.value.toLowerCase().replace(/[^a-z0-9_]/g, '')})} />
                                </>
