    try {
        const client = await pool.connect();
        try {
            await client.query('BEGIN');
            await client.query('DROP TABLE IF EXISTS system_settings');
            await client.query(`CREATE TABLE system_settings (key VARCHAR(100) PRIMARY KEY, value TEXT, description TEXT, type VARCHAR(20) DEFAULT 'text')`);
            await seedDefaultSettings(client);
            await client.query('COMMIT');
            await logSystemAction(req, 'RESET_SETTINGS', 'Khôi phục cài đặt gốc');
            res.json({ status: 'ok' });
        } catch(e) {
            await client.query('ROLLBACK');
            throw e;
        } finally {
            client.release();
        }
    } catch(e) { res.status(500).json({error: e.message}); }
});

