const initDB = async () => {
    try {
        const client = await pool.connect();
        try {
            console.log("Checking Database Schema...");

            // --- FIX: REGISTER VN-2000 (EPSG:9210) FOR BINH DUONG (105.75) ---
            try {
                await client.query(`
                    INSERT INTO spatial_ref_sys (srid, auth_name, auth_srid, srtext, proj4text)
                    VALUES (9210, 'EPSG', 9210, 
                    'PROJCS["VN2000_Binh_Duong",GEOGCS["GCS_VN_2000",DATUM["D_Vietnam_2000",SPHEROID["WGS_1984",6378137.0,298.257223563]],PRIMEM["Greenwich",0.0],UNIT["Degree",0.0174532925199433]],PROJECTION["Transverse_Mercator"],PARAMETER["False_Easting",500000.0],PARAMETER["False_Northing",0.0],PARAMETER["Central_Meridian",105.75],PARAMETER["Scale_Factor",0.9999],PARAMETER["Latitude_Of_Origin",0.0],UNIT["Meter",1.0]]', 
                    '+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.90441429,-39.30318279,-111.45032835,0.00928836,0.01975479,-0.00427372,0.252906278 +units=m +no_defs')
                    ON CONFLICT (srid) DO NOTHING;
                `);
                console.log("✅ Registered EPSG:9210 (VN-2000 Binh Duong).");
            } catch (e) {
                console.warn("⚠️ Could not register EPSG:9210 (Permission denied or exists):", e.message);
            }

            // 1. Parcels Table
            await client.query(`
                CREATE TABLE IF NOT EXISTS parcels (
                    gid SERIAL PRIMARY KEY,
                    sothua VARCHAR(50),
                    sodoto VARCHAR(50),
                    tenchu VARCHAR(255),
                    diachi TEXT,
                    dientich NUMERIC,
                    geometry GEOMETRY(Polygon, 4326),
                    properties JSONB
                )
            `);

            // 2. Users Table
            await client.query(`
                CREATE TABLE IF NOT EXISTS users (
                    id VARCHAR(50) PRIMARY KEY,
                    email VARCHAR(100) UNIQUE NOT NULL,
                    password_hash VARCHAR(255),
                    name VARCHAR(100),
                    role VARCHAR(20) DEFAULT 'VIEWER',
                    branch_id VARCHAR(50)
                )
            `);

            // 3. Branches Table
            await client.query(`
                CREATE TABLE IF NOT EXISTS branches (
                    id VARCHAR(50) PRIMARY KEY,
                    code VARCHAR(20),
                    name VARCHAR(100),
                    address TEXT
                )
            `);

            // 4. System Settings
            await client.query(`
                CREATE TABLE IF NOT EXISTS system_settings (
                    key VARCHAR(100) PRIMARY KEY,
                    value TEXT,
                    description TEXT,
                    type VARCHAR(20) DEFAULT 'text'
                )
            `);

            // Seed Settings
            await seedDefaultSettings(client);

            // 5. System Logs
            await client.query(`
                CREATE TABLE IF NOT EXISTS system_logs (
                    id SERIAL PRIMARY KEY,
                    user_id VARCHAR(50),
                    user_name VARCHAR(100),
                    action VARCHAR(50),
                    details TEXT,
                    timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    branch_id VARCHAR(50)
                )
            `);

            // --- FIX FOR MISSING SERIAL/SEQUENCE ON EXISTING SYSTEM_LOGS TABLE ---
            try {
                const logSeqCheck = await client.query(`SELECT column_default FROM information_schema.columns WHERE table_name = 'system_logs' AND column_name = 'id'`);
                if (logSeqCheck.rows.length > 0 && !logSeqCheck.rows[0].column_default) {
                    console.log("🔧 Fixing missing sequence for system_logs.id...");
                    await client.query(`CREATE SEQUENCE IF NOT EXISTS system_logs_id_seq`);
                    await client.query(`ALTER TABLE system_logs ALTER COLUMN id SET DEFAULT nextval('system_logs_id_seq')`);
                    await client.query(`SELECT setval('system_logs_id_seq', COALESCE((SELECT MAX(id) FROM system_logs), 0) + 1)`);
                    console.log("✅ Fixed system_logs sequence.");
                }
            } catch (e) {
                console.warn("⚠️ Could not auto-fix system_logs sequence:", e.message);
            }

             // 6. Land Prices
             await client.query(`
                CREATE TABLE IF NOT EXISTS land_prices (
                    land_type VARCHAR(50) PRIMARY KEY,
                    base_price NUMERIC,
                    description TEXT
                )
            `);

            // 7. WMS Layers
            await client.query(`
                CREATE TABLE IF NOT EXISTS wms_layers (
                    id VARCHAR(50) PRIMARY KEY,
                    name VARCHAR(100),
                    url TEXT,
                    layers VARCHAR(100),
                    visible BOOLEAN DEFAULT true
                )
            `);

            // 8. Role Permissions
            await client.query(`
                CREATE TABLE IF NOT EXISTS role_permissions (
                    role VARCHAR(20) PRIMARY KEY,
                    permissions JSONB
                )
            `);

            // --- SCHEMA FIXES & SEEDING (Role Permissions) ---
            try {
                // Remove duplicate roles
                await client.query(`DELETE FROM role_permissions a USING role_permissions b WHERE a.ctid < b.ctid AND a.role = b.role`);
                // Add Primary Key constraint if missing
                await client.query(`ALTER TABLE role_permissions ADD PRIMARY KEY (role)`);
            } catch (e) { /* Ignore if PK exists */ }

            // Seed Default Admin Permissions
            await client.query(`
                INSERT INTO role_permissions (role, permissions) 
                VALUES ('ADMIN', '["VIEW_MAP","EDIT_MAP","DELETE_MAP","VIEW_DASHBOARD","EXPORT_REPORT","MANAGE_USERS","MANAGE_SYSTEM","VIEW_LOGS","MANAGE_TABLES"]'::jsonb)
                ON CONFLICT (role) DO NOTHING
            `);            

            // 9. Spatial Tables Registry
            await client.query(`
                CREATE TABLE IF NOT EXISTS spatial_tables_registry (
                    table_name VARCHAR(100) PRIMARY KEY,
                    display_name VARCHAR(100),
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            `);
            console.log("✅ Database initialized: All system tables are ready.");
        } finally {
            client.release();
        }
    } catch (err) {
        console.error("⚠️ Database initialization warning:", err.message);
    }
};
