app.get('/api/proxy/vietbando', async (req, res) => {
    const { z, x, y } = req.query;
    const targetUrl = `http://images.vietbando.com/ImageLoader/GetImage.ashx?Ver=2016&LayerIds=VBD&Y=${y}&X=${x}&Level=${z}`;
    try {
        const response = await fetch(targetUrl, {
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
                'Referer': 'http://vietbando.com/',
                'Origin': 'http://vietbando.com',
                'Accept': 'image/*'
            }
        });
        if (!response.ok) throw new Error('Failed to fetch tile');
        const arrayBuffer = await response.arrayBuffer();
        const buffer = Buffer.from(arrayBuffer);
        res.set('Content-Type', 'image/png');
        res.set('Cache-Control', 'public, max-age=86400');
        res.send(buffer);
    } catch (error) {
        res.status(404).send('Tile not found');
    }
});

app.get('/api/proxy/forward', async (req, res) => {
    try {
        const { url } = req.query;
        if (!url) return res.status(400).send("Missing 'url' parameter");
        const response = await fetch(url);
        if (!response.ok) {
            return res.status(response.status).send(`Target Error: ${response.statusText}`);
        }
        const contentType = response.headers.get('content-type');
        if (contentType) res.set('Content-Type', contentType);
        const arrayBuffer = await response.arrayBuffer();
        res.send(Buffer.from(arrayBuffer));
    } catch (e) {
        console.error("Proxy Forward Error:", e.message);
        res.status(500).send({ error: e.message });
    }
});

