import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Login from './pages/Login';
import MapPage from './pages/MapPage';
import Dashboard from './pages/Dashboard';
import AdminPage from './pages/AdminPage'; // Import Admin Page
import { User, UserRole, SystemSetting } from './types';
import { Menu } from 'lucide-react';
import { adminService } from './services/mockBackend';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activePage, setActivePage] = useState('map');
  const [showLogin, setShowLogin] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [systemSettings, setSystemSettings] = useState<Record<string, string>>({});

  // Load user from local storage on boot
  useEffect(() => {
    const savedUser = localStorage.getItem('geo_user');
    if (savedUser) {
      try {
        const parsed = JSON.parse(savedUser);
        setUser(parsed);
      } catch (e) {
        localStorage.removeItem('geo_user');
      }
    }
  }, []);

  // Fetch System Settings & Apply Theme
  useEffect(() => {
      const fetchSettings = async () => {
          try {
              const settings: SystemSetting[] = await adminService.getSettings();
              const settingsMap: Record<string, string> = {};
              settings.forEach(s => settingsMap[s.key] = s.value);
              setSystemSettings(settingsMap);

              // Apply dynamic title
              if (settingsMap['system_name']) {
                  document.title = settingsMap['system_name'];
              }

              // Apply dynamic favicon
              if (settingsMap['site_favicon']) {
                  let link: HTMLLinkElement | null = document.querySelector("link[rel~='icon']");
                  if (!link) {
                      link = document.createElement('link');
                      link.rel = 'icon';
                      document.getElementsByTagName('head')[0].appendChild(link);
                  }
                  link.href = settingsMap['site_favicon'];
              }
          } catch (e) {
              console.error("Failed to load system settings", e);
          }
      };
      fetchSettings();
  }, []);

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    localStorage.setItem('geo_user', JSON.stringify(loggedInUser));
    setShowLogin(false);
    // Nếu là admin thì vào trang admin, ngược lại vào dashboard
    if (loggedInUser.role === UserRole.ADMIN) {
        setActivePage('admin');
    } else {
        setActivePage('dashboard');
    }
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('geo_user');
    setActivePage('map');
  };

  if (showLogin) {
    return (
      <Login 
        onLogin={handleLogin} 
        onCancel={() => setShowLogin(false)}
        systemName={systemSettings['system_name']}
        logoUrl={systemSettings['site_logo']}
        footerText={systemSettings['footer_text']}
      />
    );
  }

  const renderContent = () => {
    switch (activePage) {
      case 'dashboard':
        return user ? <Dashboard user={user} /> : <div className="flex h-full items-center justify-center text-gray-400">Vui lòng đăng nhập để xem báo cáo.</div>;
      case 'map':
        return <MapPage user={user} />;
      case 'admin':
        // Chỉ admin mới xem được
        return user && user.role === UserRole.ADMIN ? <AdminPage /> : <div className="p-8 text-red-400">Bạn không có quyền truy cập trang này.</div>;
      default:
        return <MapPage user={user} />;
    }
  };

  return (
    <div className="flex h-screen bg-gray-900 overflow-hidden font-sans relative">
      {!isSidebarOpen && (
        <button 
          onClick={() => setIsSidebarOpen(true)}
          className="absolute top-4 left-4 z-[500] p-2 bg-gray-900 text-white rounded shadow-md hover:bg-gray-800 transition-colors"
          title="Mở Menu"
        >
          <Menu size={20} />
        </button>
      )}

      <div 
        className={`${
          isSidebarOpen ? 'w-64 translate-x-0' : 'w-0 -translate-x-full opacity-0'
        } transition-all duration-300 ease-in-out bg-gray-900 shadow-xl z-50 overflow-hidden`}
      >
        <Sidebar 
          user={user} 
          activePage={activePage} 
          onNavigate={setActivePage} 
          onLogout={handleLogout}
          onLoginClick={() => setShowLogin(true)}
          onCollapse={() => setIsSidebarOpen(false)}
          systemName={systemSettings['system_name']}
          logoUrl={systemSettings['site_logo']}
        />
      </div>

      <main className="flex-1 relative overflow-hidden bg-gray-100">
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { User, UserRole } from '../types';
import { Map, LayoutDashboard, LogOut, Shield, Database, LogIn, ChevronLeft } from 'lucide-react';

interface SidebarProps {
  user: User | null;
  activePage: string;
  onNavigate: (page: string) => void;
  onLogout: () => void;
  onLoginClick: () => void;
  onCollapse: () => void;
  systemName?: string;
  logoUrl?: string;
}

const Sidebar: React.FC<SidebarProps> = ({ user, activePage, onNavigate, onLogout, onLoginClick, onCollapse, systemName, logoUrl }) => {
  const menuItems = [
    { id: 'dashboard', label: 'Bảng điều khiển', icon: LayoutDashboard, roles: [UserRole.ADMIN, UserRole.EDITOR, UserRole.VIEWER] },
    { id: 'map', label: 'Bản đồ WebGIS', icon: Map, roles: ['GUEST', UserRole.ADMIN, UserRole.EDITOR, UserRole.VIEWER] },
    { id: 'admin', label: 'Quản trị hệ thống', icon: Shield, roles: [UserRole.ADMIN] },
  ];

  // Filter items based on user role or guest status
  const visibleItems = menuItems.filter(item => {
    if (!user) {
      return item.roles.includes('GUEST');
    }
    return item.roles.includes(user.role);
  });

  return (
    <div className="w-64 bg-gray-900 text-white h-screen flex flex-col">
      <div className="p-6 border-b border-gray-800 flex justify-between items-center">
        <div>
            {logoUrl ? (
                <div className="flex items-center gap-2 mb-2">
                    <img src={logoUrl} alt="Logo" className="w-10 h-10 object-contain" />
                    <h1 className="text-xl font-bold text-blue-400 leading-tight">
                        {systemName || 'GeoMaster'}
                    </h1>
                </div>
            ) : (
                <h1 className="text-2xl font-bold text-blue-400 flex items-center gap-2">
                    <Database className="w-6 h-6" />
                    {systemName || 'GeoMaster'}
                </h1>
            )}
            <p className="text-xs text-gray-500 mt-1">v2.5.0 Enterprise VN</p>
        </div>
        <button onClick={onCollapse} className="text-gray-500 hover:text-white p-1" title="Thu gọn menu">
            <ChevronLeft size={20} />
        </button>
      </div>

      <div className="flex-1 py-6">
        {visibleItems.map(item => (
          <button
            key={item.id}
            onClick={() => onNavigate(item.id)}
            className={`w-full flex items-center gap-4 px-6 py-3 transition-colors ${
              activePage === item.id 
                ? 'bg-blue-600 text-white border-r-4 border-blue-300' 
                : 'text-gray-400 hover:bg-gray-800 hover:text-white'
            }`}
          >
            <item.icon size={20} />
            <span className="font-medium">{item.label}</span>
          </button>
        ))}
      </div>

      <div className="p-6 border-t border-gray-800">
        {user ? (
          <>
            <div className="mb-4">
                <p className="text-sm font-semibold text-white">{user.name}</p>
                <p className="text-xs text-gray-500 uppercase">{user.role}</p>
            </div>
            <button 
              onClick={onLogout}
              className="w-full flex items-center gap-2 px-4 py-2 bg-red-600/20 text-red-400 rounded hover:bg-red-600 hover:text-white transition-all"
            >
              <LogOut size={16} />
              Đăng xuất
            </button>
          </>
        ) : (
          <button 
            onClick={onLoginClick}
            className="w-full flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-500 transition-all"
          >
            <LogIn size={16} />
            Đăng nhập
          </button>
        )}
      </div>
    </div>
  );
};

