interface LoginProps {
  onLogin: (user: User) => void;
  onCancel: () => void;
  systemName?: string;
  logoUrl?: string;
  footerText?: string;
}

const Login: React.FC<LoginProps> = ({ onLogin, onCancel, systemName, logoUrl, footerText }) => {
  const [view, setView] = useState<'LOGIN' | 'FORGOT' | 'OTP' | 'REGISTER'>('LOGIN');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Login State
  const [email, setEmail] = useState('thai@gmail.com');
  const [password, setPassword] = useState('123@');

  // Register State
  const [regName, setRegName] = useState('');
  const [regEmail, setRegEmail] = useState('');
  const [regPassword, setRegPassword] = useState('');
  const [regBranch, setRegBranch] = useState('');
  const [branches, setBranches] = useState<Branch[]>([]);

  // OTP State
  const [otp, setOtp] = useState('');

  // Load branches when switching to Register view
  useEffect(() => {
    if (view === 'REGISTER') {
        const loadBranches = async () => {
            const data = await authService.getBranches();
            setBranches(data);
            if (data.length > 0) setRegBranch(data[0].id);
        };
        loadBranches();
    }
  }, [view]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const user = await authService.login(email, password);
      onLogin(user);
    } catch (err) {
      setError('Email hoặc mật khẩu không đúng');
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
      e.preventDefault();
      setLoading(true);
      setError('');
      try {
          if (!regBranch) throw new Error('Vui lòng chọn chi nhánh');
          await authService.register(regName, regEmail, regBranch);
          alert('Đăng ký thành công! Vui lòng đăng nhập bằng mật khẩu 123456 (Mặc định cho Demo).');
          setView('LOGIN');
          setEmail(regEmail);
