        {/* --- VIEW: REGISTER --- */}
        {view === 'REGISTER' && (
             <form onSubmit={handleRegister} className="space-y-4">
                <div>
                  <label className="block text-gray-400 text-xs uppercase font-bold mb-1">Họ và Tên</label>
                  <div className="relative">
                    <UserIcon className="absolute left-3 top-2.5 text-gray-500" size={16} />
                    <input
                      type="text"
                      value={regName}
                      onChange={(e) => setRegName(e.target.value)}
                      className="w-full bg-gray-700 border border-gray-600 rounded p-2 pl-10 text-white focus:border-blue-500 outline-none"
                      required
                      placeholder="Nguyễn Văn A"
                    />
                  </div>
