                <div>
                  <label className="block text-gray-400 text-xs uppercase font-bold mb-1">Email</label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-2.5 text-gray-500" size={16} />
                    <input
                      type="email"
                      value={regEmail}
                      onChange={(e) => setRegEmail(e.target.value)}
                      className="w-full bg-gray-700 border border-gray-600 rounded p-2 pl-10 text-white focus:border-blue-500 outline-none"
                      required
                      placeholder="email@example.com"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-gray-400 text-xs uppercase font-bold mb-1">Mật khẩu</label>
                  <div className="relative">
                    <Lock className="absolute left-3 top-2.5 text-gray-500" size={16} />
                    <input
                      type="password"
                      value={regPassword}
                      onChange={(e) => setRegPassword(e.target.value)}
                      className="w-full bg-gray-700 border border-gray-600 rounded p-2 pl-10 text-white focus:border-blue-500 outline-none"
                      required
                      placeholder="••••••"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-gray-400 text-xs uppercase font-bold mb-1">Chi nhánh công tác</label>
                  <div className="relative">
                    <Building className="absolute left-3 top-2.5 text-gray-500" size={16} />
                    <select
                      value={regBranch}
                      onChange={(e) => setRegBranch(e.target.value)}
                      className="w-full bg-gray-700 border border-gray-600 rounded p-2 pl-10 text-white focus:border-blue-500 outline-none appearance-none"
                      required
                    >
                        {branches.map(b => (
                            <option key={b.id} value={b.id}>{b.name}</option>
                        ))}
