                  </div>
                </div>

                <button
                  type="submit"
                  disabled={loading}
                  className="w-full bg-green-600 hover:bg-green-500 text-white font-semibold py-3 rounded mt-2 transition-all flex justify-center items-center gap-2"
                >
                  {loading ? <Loader2 className="animate-spin" size={20} /> : <><UserPlus size={18} /> Đăng ký</>}
                </button>

                <div className="text-center mt-2">
                    <button type="button" onClick={() => setView('LOGIN')} className="text-sm text-gray-400 hover:text-white">
                        Đã có tài khoản? Đăng nhập
