        {/* --- VIEW: FORGOT PASSWORD --- */}
        {view === 'FORGOT' && (
            <div className="space-y-6">
                <p className="text-gray-300 text-sm">Nhập email của bạn để nhận mã xác thực (OTP) đặt lại mật khẩu.</p>
