            <div className="mt-6 pt-4 border-t border-gray-700 flex justify-center">
                 <button type="button" onClick={onCancel} className="text-gray-500 text-xs hover:text-white flex items-center gap-1">
                    <ArrowLeft size={12} /> Quay lại trang chủ
                </button>
            </div>
        )}
      </div>
    </div>
  );
};

