import React, { useEffect, useState } from 'react';
import { adminService, PERMISSIONS_LIST } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { User, Branch, SystemLog, LandPriceConfig, UserRole, SystemSetting, WMSLayerConfig, RoleConfig } from '../types';
import { Edit2, Trash2, CheckCircle, Save, Settings, AlertOctagon, Activity, AlertTriangle, X, Layers, Database, Plus, Table, Link, ShieldCheck, Wrench, PenTool, Link2Off, RefreshCw, Server, Cpu, HardDrive, Monitor, Upload, Image as ImageIcon } from 'lucide-react';
import AdminMenu from '../components/AdminMenu';
import ParcelManager from './ParcelManager';

const AdminPage: React.FC = () => {
    const [activeTab, setActiveTab] = useState('PARCEL_MANAGER'); 

    // Data states
    const [users, setUsers] = useState<User[]>([]);
    const [branches, setBranches] = useState<Branch[]>([]);
    const [prices, setPrices] = useState<LandPriceConfig[]>([]);
    const [logs, setLogs] = useState<SystemLog[]>([]);
    const [settings, setSettings] = useState<SystemSetting[]>([]);
    const [wmsLayers, setWmsLayers] = useState<WMSLayerConfig[]>([]);
    const [spatialTables, setSpatialTables] = useState<string[]>([]);
    const [rolePermissions, setRolePermissions] = useState<RoleConfig[]>([]);
    const [serverInfo, setServerInfo] = useState<any>(null);

    // Connection Status
    const [dbStatus, setDbStatus] = useState<{status: 'checking' | 'connected' | 'error', message?: string, dbName?: string, host?: string, port?: string, user?: string}>({ status: 'checking' });

    // Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalType, setModalType] = useState<'USER' | 'BRANCH' | 'PRICE' | 'LAYER' | 'TABLE' | 'RENAME_TABLE' | null>(null);
    const [editingItem, setEditingItem] = useState<any>(null);
    const [formData, setFormData] = useState<any>({});

    // Delete Modal State
    const [deleteModal, setDeleteModal] = useState<{isOpen: boolean, id: string | null, type: 'USER' | 'BRANCH' | 'PRICE' | 'LAYER' | 'TABLE' | 'UNLINK_TABLE' | null}>({isOpen: false, id: null, type: null});

    useEffect(() => {
        checkConnection();
        loadData();
    }, [activeTab]);

    const checkConnection = async () => {
        setDbStatus({ status: 'checking' });
        try {
            const res = await adminService.checkDbConnection();
            if (res.status === 'connected') {
                setDbStatus({ 
                    status: 'connected', 
                    dbName: res.database,
                    host: res.host || 'localhost',
                    port: res.port || '5432',
                    user: res.user || 'postgres'
                });
            } else {
                setDbStatus({ status: 'error', message: 'Lỗi Database' });
            }
        } catch (error: any) {
            setDbStatus({ status: 'error', message: error.message });
        }
    };

    const loadData = async () => {
        if (activeTab === 'PARCEL_MANAGER') return; 
        try {
            // Load branches immediately if on users tab to populate dropdown
            if (activeTab === 'USERS') {
                 setUsers(await adminService.getUsers().catch(() => []));
                 setBranches(await adminService.getBranches().catch(() => []));
            }
            if (activeTab === 'BRANCHES') setBranches(await adminService.getBranches().catch(() => []));
            if (activeTab === 'PRICES') setPrices(await adminService.getPrices().catch(() => []));
            if (activeTab === 'LOGS') setLogs(await adminService.getLogs().catch(() => []));
            if (activeTab === 'SETTINGS') {
                setSettings(await adminService.getSettings().catch(() => []));
                setServerInfo(await adminService.getServerInfo().catch(() => null));
            }
            if (activeTab === 'PERMISSIONS') setRolePermissions(await adminService.getRolePermissions().catch(() => []));
            if (activeTab === 'DATA_LAYERS') {
                setWmsLayers(await adminService.getWmsLayers().catch(() => []));
                setSpatialTables(await parcelApi.manageTables.getAll().catch(() => []));
            }
        } catch (e) {
            console.error("Lỗi tải dữ liệu admin", e);
        }
    };

    // --- HANDLERS ---
    const openModal = (type: 'USER' | 'BRANCH' | 'PRICE' | 'LAYER' | 'TABLE' | 'RENAME_TABLE', item?: any) => {
        setModalType(type);
        setEditingItem(item || null);
        if (item) setFormData({ ...item });
        else {
            if (type === 'USER') setFormData({ role: UserRole.VIEWER, branchId: branches[0]?.id || '', name: '', email: '', password: '' });
            if (type === 'BRANCH') setFormData({ code: '', name: '', address: '' });
            if (type === 'PRICE') setFormData({ landType: '', basePrice: '' });
            if (type === 'LAYER') setFormData({ name: '', url: 'http://171.246.238.230/geoserver/wms', layers: '', visible: true });
            if (type === 'TABLE') setFormData({ tableName: '', isExisting: false });
        }

        if (type === 'RENAME_TABLE') {
             // item is the old table name string
             setFormData({ oldName: item, newName: item });
        }

        setIsModalOpen(true);
    };

    const closeModal = () => { setIsModalOpen(false); setEditingItem(null); setFormData({}); };

    const handleSave = async () => {
        try {
            if (modalType === 'USER') {
                 if (editingItem) await adminService.updateUser(formData); else await adminService.addUser(formData);
            } else if (modalType === 'BRANCH') {
                 if (editingItem) await adminService.updateBranch(formData); else await adminService.addBranch(formData);
            } else if (modalType === 'PRICE') {
                 if (editingItem) await adminService.updatePrice(editingItem.landType, Number(formData.basePrice)); else await adminService.addPrice(formData);
            } else if (modalType === 'LAYER') {
                 if (editingItem) await adminService.updateWmsLayer(formData); else await adminService.addWmsLayer(formData); 
            } else if (modalType === 'TABLE') {
                 if (formData.isExisting) {
                    await parcelApi.manageTables.link(formData.tableName);
                 } else {
                    await parcelApi.manageTables.create(formData.tableName);
                 }
            } else if (modalType === 'RENAME_TABLE') {
                 await parcelApi.manageTables.rename(formData.oldName, formData.newName);
            }
            closeModal(); loadData(); alert("Thành công!");
        } catch(e: any) { alert(e.message); }
    };

    // Trigger Delete
