                        <h3 className="text-white font-bold text-sm">
                            {systemName || 'Quản Trị Viên'}
                        </h3>
                    </div>
                ) : (
                    <h3 className="text-white font-bold flex items-center gap-2 text-lg">
                        <Database className="text-blue-500" />
                        Quản Trị Viên
                    </h3>
                )}
                <p className="text-xs text-gray-500 mt-1">Hệ thống GIS Trung tâm</p>
            </div>

            <nav className="flex-1 p-4 space-y-1 overflow-y-auto custom-scrollbar">
                {menuItems.map((item: any, index) => (
                    item.header ? (
                        <div key={`head-${index}`} className="mt-6 mb-2 px-4 text-xs font-bold text-gray-500 uppercase tracking-wider">
                            {item.header}
                        </div>
                    ) : (
                        <button
                            key={item.id}
                            onClick={() => onSelect(item.id)}
                            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-200 group ${
                                activeTab === item.id 
                                ? 'bg-blue-600 text-white shadow-lg translate-x-1' 
                                : item.highlight 
                                    ? 'text-blue-400 hover:bg-blue-900/20 hover:text-blue-300' 
                                    : 'text-gray-400 hover:bg-gray-700 hover:text-white'
                            }`}
                        >
                            <item.icon size={18} className={`${activeTab === item.id ? 'text-white' : ''} group-hover:scale-110 transition-transform`} />
                            <span className="font-medium text-sm">{item.label}</span>
                        </button>
                    )
                ))}
            </nav>

            <div className="p-4 border-t border-gray-700 text-xs text-center text-gray-500">
                GeoMaster v2.5.0 Admin
            </div>
        </div>
    );
};

export default AdminMenu;

import React, { useEffect, useState } from 'react';
import { adminService, PERMISSIONS_LIST } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { User, Branch, SystemLog, LandPriceConfig, UserRole, SystemSetting, WMSLayerConfig, RoleConfig } from '../types';
import { Edit2, Trash2, CheckCircle, Save, Settings, AlertOctagon, Activity, AlertTriangle, X, Layers, Database, Plus, Table, Link, ShieldCheck, Wrench, PenTool, Link2Off, RefreshCw, Server, Cpu, HardDrive, Monitor, Upload, Image as ImageIcon } from 'lucide-react';
import AdminMenu from '../components/AdminMenu';
import ParcelManager from './ParcelManager';

interface AdminPageProps {
    systemName?: string;
    logoUrl?: string;
}

const AdminPage: React.FC<AdminPageProps> = ({ systemName, logoUrl }) => {
    const [activeTab, setActiveTab] = useState('PARCEL_MANAGER'); 

    // Data states
    const [users, setUsers] = useState<User[]>([]);
    const [branches, setBranches] = useState<Branch[]>([]);
    const [prices, setPrices] = useState<LandPriceConfig[]>([]);
    const [logs, setLogs] = useState<SystemLog[]>([]);
    const [settings, setSettings] = useState<SystemSetting[]>([]);
    const [wmsLayers, setWmsLayers] = useState<WMSLayerConfig[]>([]);
    const [spatialTables, setSpatialTables] = useState<string[]>([]);
    const [rolePermissions, setRolePermissions] = useState<RoleConfig[]>([]);
    const [serverInfo, setServerInfo] = useState<any>(null);

    // Connection Status
    const [dbStatus, setDbStatus] = useState<{status: 'checking' | 'connected' | 'error', message?: string, dbName?: string, host?: string, port?: string, user?: string}>({ status: 'checking' });

    // Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalType, setModalType] = useState<'USER' | 'BRANCH' | 'PRICE' | 'LAYER' | 'TABLE' | 'RENAME_TABLE' | null>(null);
    const [editingItem, setEditingItem] = useState<any>(null);
    const [formData, setFormData] = useState<any>({});

    // Delete Modal State
    const [deleteModal, setDeleteModal] = useState<{isOpen: boolean, id: string | null, type: 'USER' | 'BRANCH' | 'PRICE' | 'LAYER' | 'TABLE' | 'UNLINK_TABLE' | null}>({isOpen: false, id: null, type: null});

    useEffect(() => {
        checkConnection();
        loadData();
    }, [activeTab]);

    const checkConnection = async () => {
        setDbStatus({ status: 'checking' });
        try {
            const res = await adminService.checkDbConnection();
            if (res.status === 'connected') {
                setDbStatus({ 
                    status: 'connected', 
                    dbName: res.database,
                    host: res.host || 'localhost',
                    port: res.port || '5432',
                    user: res.user || 'postgres'
                });
            } else {
                setDbStatus({ status: 'error', message: 'Lỗi Database' });
            }
        } catch (error: any) {
            setDbStatus({ status: 'error', message: error.message });
        }
    };

    const loadData = async () => {
        if (activeTab === 'PARCEL_MANAGER') return; 
        try {
            // Load branches immediately if on users tab to populate dropdown
            if (activeTab === 'USERS') {
                 setUsers(await adminService.getUsers().catch(() => []));
                 setBranches(await adminService.getBranches().catch(() => []));
            }
            if (activeTab === 'BRANCHES') setBranches(await adminService.getBranches().catch(() => []));
            if (activeTab === 'PRICES') setPrices(await adminService.getPrices().catch(() => []));
            if (activeTab === 'LOGS') setLogs(await adminService.getLogs().catch(() => []));
            if (activeTab === 'SETTINGS') {
                setSettings(await adminService.getSettings().catch(() => []));
                setServerInfo(await adminService.getServerInfo().catch(() => null));
            }
            if (activeTab === 'PERMISSIONS') setRolePermissions(await adminService.getRolePermissions().catch(() => []));
            if (activeTab === 'DATA_LAYERS') {
                setWmsLayers(await adminService.getWmsLayers().catch(() => []));
                setSpatialTables(await parcelApi.manageTables.getAll().catch(() => []));
            }
        } catch (e) {
            console.error("Lỗi tải dữ liệu admin", e);
        }
    };

    // --- HANDLERS ---
    const openModal = (type: 'USER' | 'BRANCH' | 'PRICE' | 'LAYER' | 'TABLE' | 'RENAME_TABLE', item?: any) => {
        setModalType(type);
        setEditingItem(item || null);
        if (item) setFormData({ ...item });
        else {
            if (type === 'USER') setFormData({ role: UserRole.VIEWER, branchId: branches[0]?.id || '', name: '', email: '', password: '' });
            if (type === 'BRANCH') setFormData({ code: '', name: '', address: '' });
            if (type === 'PRICE') setFormData({ landType: '', basePrice: '' });
            if (type === 'LAYER') setFormData({ name: '', url: 'http://171.246.238.230/geoserver/wms', layers: '', visible: true });
            if (type === 'TABLE') setFormData({ tableName: '', isExisting: false });
        }

        if (type === 'RENAME_TABLE') {
             // item is the old table name string
             setFormData({ oldName: item, newName: item });
        }

        setIsModalOpen(true);
    };

    const closeModal = () => { setIsModalOpen(false); setEditingItem(null); setFormData({}); };

    const handleSave = async () => {
        try {
            if (modalType === 'USER') {
                 if (editingItem) await adminService.updateUser(formData); else await adminService.addUser(formData);
            } else if (modalType === 'BRANCH') {
                 if (editingItem) await adminService.updateBranch(formData); else await adminService.addBranch(formData);
            } else if (modalType === 'PRICE') {
                 if (editingItem) await adminService.updatePrice(editingItem.landType, Number(formData.basePrice)); else await adminService.addPrice(formData);
            } else if (modalType === 'LAYER') {
                 if (editingItem) await adminService.updateWmsLayer(formData); else await adminService.addWmsLayer(formData); 
            } else if (modalType === 'TABLE') {
                 if (formData.isExisting) {
                    await parcelApi.manageTables.link(formData.tableName);
                 } else {
                    await parcelApi.manageTables.create(formData.tableName);
                 }
            } else if (modalType === 'RENAME_TABLE') {
                 await parcelApi.manageTables.rename(formData.oldName, formData.newName);
            }
            closeModal(); loadData(); alert("Thành công!");
        } catch(e: any) { alert(e.message); }
    };

    // Trigger Delete
    const initiateDelete = (id: string, type: 'USER' | 'BRANCH' | 'PRICE' | 'LAYER' | 'TABLE' | 'UNLINK_TABLE') => {
        setDeleteModal({ isOpen: true, id, type });
    };

    const handleNormalizeTable = async (tableName: string) => {
        if (!confirm(`Bạn có muốn chuẩn hóa bảng '${tableName}' không? Hệ thống sẽ tự động thêm các cột chuẩn (sothua, sodoto...) nếu thiếu.`)) return;
        try {
            await parcelApi.manageTables.link(tableName);
            alert(`Đã chuẩn hóa bảng '${tableName}' thành công!`);
            loadData();
        } catch (e: any) {
            alert("Lỗi chuẩn hóa: " + e.message);
        }
    };

    // Execute Delete
    const executeDelete = async () => {
        const { id, type } = deleteModal;
        if (!id || !type) return;

        try {
            if (type === 'USER') await adminService.deleteUser(id);
            if (type === 'BRANCH') await adminService.deleteBranch(id);
            if (type === 'PRICE') await adminService.deletePrice(id);
            if (type === 'LAYER') await adminService.deleteWmsLayer(id);

            if (type === 'TABLE') await parcelApi.manageTables.delete(id);
            if (type === 'UNLINK_TABLE') await parcelApi.manageTables.unlink(id);

            setDeleteModal({ isOpen: false, id: null, type: null });
            loadData();
        } catch(e:any) { alert(e.message); }
    };

    const handleSettingChange = (key: string, value: string) => {
        setSettings(prev => prev.map(s => s.key === key ? { ...s, value } : s));
    };

    // Handle Image File Selection and Conversion to Base64
    const handleImageUpload = (key: string, event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (!file) return;

        // Validations
        if (!file.type.startsWith('image/')) {
            alert("Vui lòng chỉ chọn file ảnh (png, jpg, ico, svg)");
            return;
        }
        if (file.size > 2 * 1024 * 1024) { // 2MB limit
            alert("Kích thước ảnh quá lớn. Vui lòng chọn ảnh < 2MB");
            return;
        }

        const reader = new FileReader();
        reader.onloadend = () => {
            const base64String = reader.result as string;
            handleSettingChange(key, base64String);
        };
        reader.readAsDataURL(file);
    };

    const saveSettings = async () => {
        try {
            await adminService.saveSettings(settings);
            alert("Đã lưu cấu hình hệ thống! Vui lòng tải lại trang để thấy thay đổi.");
            // Optional: reload page to apply logo/favicon instantly
            window.location.reload(); 
        } catch (e: any) {
            alert("Lỗi lưu cấu hình: " + e.message);
        }
    };

    const handleResetFactory = async () => {
        if (!confirm("CẢNH BÁO: Bạn có chắc chắn muốn đặt lại toàn bộ cài đặt về mặc định không?")) return;
        try {
            await adminService.resetSettings();
            alert("Đã khôi phục cài đặt gốc thành công! Trang web sẽ tự tải lại.");
            window.location.reload(); // Reload page
        } catch (e: any) {
            alert("Lỗi reset: " + e.message);
        }
    };

    const handlePermissionChange = async (role: UserRole, permissionCode: string, checked: boolean) => {
        const currentConfig = rolePermissions.find(r => r.role === role);
        let newPermissions = currentConfig ? [...currentConfig.permissions] : [];

        if (checked) {
            if (!newPermissions.includes(permissionCode)) newPermissions.push(permissionCode);
        } else {
            newPermissions = newPermissions.filter(p => p !== permissionCode);
        }

        try {
            await adminService.saveRolePermissions(role, newPermissions);
            // Optimistic update
            setRolePermissions(prev => {
                const idx = prev.findIndex(r => r.role === role);
                if (idx === -1) return [...prev, { role, permissions: newPermissions }];
                const updated = [...prev];
                updated[idx] = { ...updated[idx], permissions: newPermissions };
                return updated;
            });
        } catch (e: any) { alert(e.message); }
    };

    const formatBytes = (bytes: number) => {
        if (bytes === 0) return '0 Bytes';
        const k = 1024;
        const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    };

    // --- DB STATUS RENDER ---
    const renderDbStatus = () => {
         if (dbStatus.status === 'checking') return <div className="text-gray-400 text-xs animate-pulse">Đang kết nối DB...</div>;
         if (dbStatus.status === 'connected') return <div className="text-green-400 text-xs flex items-center gap-1"><CheckCircle size={12}/> {dbStatus.dbName}</div>;
         return <div onClick={checkConnection} className="text-red-400 text-xs cursor-pointer font-bold">Mất kết nối DB</div>;
    };

    return (
        <div className="flex h-full bg-gray-900 text-white overflow-hidden font-sans">
            <AdminMenu 
                activeTab={activeTab} 
                onSelect={setActiveTab} 
                systemName={systemName}
                logoUrl={logoUrl}
            />

            <div className="flex-1 flex flex-col h-full overflow-hidden bg-gray-900">
                <div className="bg-gray-800 p-4 border-b border-gray-700 flex justify-between items-center shadow-md z-10">
                    <div>
                        <h2 className="text-xl font-bold text-gray-100 tracking-tight flex items-center gap-2">
                            {activeTab === 'PARCEL_MANAGER' && 'Quản lý Dữ liệu Thửa đất'}
                            {activeTab === 'USERS' && 'Quản lý Người dùng'}
                            {activeTab === 'PERMISSIONS' && 'Phân quyền & Vai trò'}
                            {activeTab === 'BRANCHES' && 'Quản lý Chi nhánh'}
                            {activeTab === 'PRICES' && 'Bảng Giá đất'}
                            {activeTab === 'LOGS' && <><Activity className="text-orange-500" /> Nhật ký Hệ thống</>}
                            {activeTab === 'SETTINGS' && <><Settings className="text-blue-500" /> Thiết lập Hệ thống</>}
                            {activeTab === 'DATA_LAYERS' && <><Layers className="text-purple-500" /> Quản lý Nguồn Dữ liệu</>}
                        </h2>
                    </div>
                    {renderDbStatus()}
                </div>

                <div className="flex-1 overflow-auto bg-gray-900 relative custom-scrollbar">
                    {activeTab === 'PARCEL_MANAGER' ? (
                        <ParcelManager />
                    ) : (
                        <div className="p-8">
                            {/* --- TAB: USERS --- */}
                            {activeTab === 'USERS' && (
                                <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl overflow-hidden">
                                    <div className="p-4 flex justify-between border-b border-gray-700 bg-gray-800">
                                        <span className="font-semibold text-gray-300">Danh sách Người dùng Hệ thống</span>
                                        <button onClick={() => openModal('USER')} className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-1.5 rounded text-sm font-medium">+ Thêm mới</button>
                                    </div>
                                    <table className="w-full text-sm text-left text-gray-300">
                                        <thead className="bg-gray-900 text-gray-400 uppercase text-xs"><tr><th className="p-4">Tên</th><th className="p-4">Email</th><th className="p-4">Quyền</th><th className="p-4">Chi nhánh</th><th className="p-4 text-right">Hành động</th></tr></thead>
                                        <tbody className="divide-y divide-gray-700">
                                            {users.map(u => (
                                                <tr key={u.id} className="hover:bg-gray-700/50 transition-colors">
                                                    <td className="p-4 font-medium text-white">{u.name}</td><td className="p-4">{u.email}</td>
                                                    <td className="p-4"><span className={`px-2 py-1 rounded text-xs font-bold ${u.role==='ADMIN'?'bg-red-900 text-red-300':'bg-blue-900 text-blue-300'}`}>{u.role}</span></td>
                                                    <td className="p-4 text-gray-400">{u.branchId}</td>
                                                    <td className="p-4 flex justify-end gap-3">
                                                        <button onClick={() => openModal('USER', u)} className="text-blue-400 hover:text-white"><Edit2 size={16}/></button>
                                                        <button onClick={() => initiateDelete(u.id, 'USER')} className="text-red-400 hover:text-white"><Trash2 size={16}/></button>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            )}

                            {/* --- TAB: PERMISSIONS (NEW) --- */}
                            {activeTab === 'PERMISSIONS' && (
                                <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl overflow-hidden">
                                    <div className="p-6 border-b border-gray-700 bg-gray-800">
                                        <h3 className="font-bold text-white text-lg flex items-center gap-2"><ShieldCheck className="text-green-500"/> Ma trận Phân quyền</h3>
                                        <p className="text-gray-400 text-sm mt-1">Đánh dấu vào các ô để cấp quyền cho từng nhóm vai trò.</p>
                                    </div>
                                    <div className="overflow-x-auto">
                                        <table className="w-full text-sm text-left text-gray-300">
                                            <thead className="bg-gray-900 text-gray-400 uppercase text-xs">
                                                <tr>
                                                    <th className="p-4 w-1/3">Chức năng</th>
                                                    <th className="p-4 text-center">ADMIN</th>
                                                    <th className="p-4 text-center">EDITOR</th>
                                                    <th className="p-4 text-center">VIEWER</th>
                                                </tr>
                                            </thead>
                                            <tbody className="divide-y divide-gray-700">
                                                {PERMISSIONS_LIST.map((perm) => (
                                                    <tr key={perm.code} className="hover:bg-gray-700/30 transition-colors">
                                                        <td className="p-4">
                                                            <div className="font-bold text-gray-200">{perm.name}</div>
                                                            <div className="text-xs text-gray-500 font-mono mt-0.5">{perm.code}</div>
                                                        </td>
                                                        {[UserRole.ADMIN, UserRole.EDITOR, UserRole.VIEWER].map(role => {
                                                            const roleConfig = rolePermissions.find(r => r.role === role);
                                                            const hasPermission = roleConfig?.permissions.includes(perm.code);
                                                            return (
                                                                <td key={role} className="p-4 text-center">
                                                                    <input 
                                                                        type="checkbox" 
                                                                        className="w-5 h-5 rounded border-gray-600 text-blue-600 focus:ring-blue-500 bg-gray-700 cursor-pointer"
                                                                        checked={!!hasPermission}
                                                                        onChange={(e) => handlePermissionChange(role, perm.code, e.target.checked)}
                                                                    />
                                                                </td>
                                                            );
                                                        })}
                                                    </tr>
                                                ))}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
                            )}

                            {/* --- TAB: BRANCHES --- */}
                            {activeTab === 'BRANCHES' && (
                                <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl overflow-hidden">
                                    <div className="p-4 flex justify-between border-b border-gray-700">
                                        <span className="font-semibold text-gray-300">Danh sách Chi nhánh</span>
                                        <button onClick={() => openModal('BRANCH')} className="bg-green-600 hover:bg-green-500 text-white px-4 py-1.5 rounded text-sm font-medium">+ Thêm mới</button>
                                    </div>
                                    <table className="w-full text-sm text-left text-gray-300">
                                        <thead className="bg-gray-900 text-gray-400 uppercase text-xs"><tr><th className="p-4">Mã</th><th className="p-4">Tên Chi nhánh</th><th className="p-4">Địa chỉ</th><th className="p-4 text-right">Hành động</th></tr></thead>
                                        <tbody className="divide-y divide-gray-700">
                                            {branches.map(b => (
                                                <tr key={b.id} className="hover:bg-gray-700/50 transition-colors">
                                                    <td className="p-4 font-mono text-blue-300">{b.code}</td><td className="p-4 font-medium text-white">{b.name}</td><td className="p-4 text-gray-400">{b.address}</td>
                                                    <td className="p-4 flex justify-end gap-3">
                                                        <button onClick={() => openModal('BRANCH', b)} className="text-blue-400 hover:text-white"><Edit2 size={16}/></button>
                                                        <button onClick={() => initiateDelete(b.id, 'BRANCH')} className="text-red-400 hover:text-white"><Trash2 size={16}/></button>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            )}

                            {/* --- TAB: PRICES --- */}
                            {activeTab === 'PRICES' && (
                                 <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl overflow-hidden">
                                    <div className="p-4 flex justify-between border-b border-gray-700">
                                        <span className="font-semibold text-gray-300">Cấu hình Giá đất</span>
                                        <button onClick={() => openModal('PRICE')} className="bg-green-600 hover:bg-green-500 text-white px-4 py-1.5 rounded text-sm font-medium">+ Thêm mới</button>
                                    </div>
                                    <table className="w-full text-sm text-left text-gray-300">
                                        <thead className="bg-gray-900 text-gray-400 uppercase text-xs"><tr><th className="p-4">Loại Đất</th><th className="p-4 text-right">Giá Cơ sở (VNĐ/m²)</th><th className="p-4 text-right">Hành động</th></tr></thead>
                                        <tbody className="divide-y divide-gray-700">
                                            {prices.map((p, idx) => (
                                                <tr key={idx} className="hover:bg-gray-700/50 transition-colors">
                                                    <td className="p-4 font-medium text-white">{p.landType}</td><td className="p-4 text-right font-mono text-green-400">{Number(p.basePrice).toLocaleString()}</td>
                                                    <td className="p-4 flex justify-end gap-3">
                                                        <button onClick={() => openModal('PRICE', p)} className="text-blue-400 hover:text-white"><Edit2 size={16}/></button>
                                                        <button onClick={() => initiateDelete(p.landType, 'PRICE')} className="text-red-400 hover:text-white"><Trash2 size={16}/></button>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                 </div>
                            )}

                            {/* --- TAB: DATA_LAYERS (NEW) --- */}
                            {activeTab === 'DATA_LAYERS' && (
                                <div className="space-y-6">
                                    {/* DB Connection Config */}
                                    <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl p-6">
                                         <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2"><Database className="text-blue-400" /> Cấu hình Kết nối Database (Hiện tại)</h3>
                                         <p className="text-gray-400 text-sm mb-4">Thông tin kết nối thực tế mà Server Backend đang sử dụng.</p>

                                         <div className="bg-gray-900 p-4 rounded border border-gray-600 font-mono text-sm text-gray-300 flex flex-col gap-2">
                                             <div className="flex justify-between">
                                                <span className="text-gray-500">Host / Port:</span>
                                                <span className="text-green-400">{dbStatus.host || 'localhost'} : {dbStatus.port || '5432'}</span>
                                             </div>
                                             <div className="flex justify-between">
                                                <span className="text-gray-500">Database Name:</span>
                                                <span className="text-blue-400 font-bold">{dbStatus.dbName || '...'}</span>
                                             </div>
                                              <div className="flex justify-between">
                                                <span className="text-gray-500">User:</span>
                                                <span className="text-yellow-400">{dbStatus.user || 'postgres'}</span>
                                             </div>
                                         </div>
