              <button onClick={() => setFetchError(null)} className="mt-2 w-full bg-white text-red-900 font-bold py-2 rounded hover:bg-gray-200 flex items-center justify-center gap-2">
                  <X size={16} /> Đóng
              </button>
          </div>
      )}

      {/* Search Box */}
      <div className="absolute top-4 left-16 z-[400] flex flex-col gap-2">
           <button onClick={() => setIsSearchOpen(!isSearchOpen)} className={`p-3 bg-white rounded-lg shadow-lg hover:bg-gray-50 text-gray-700 transition-all ${isSearchOpen ? 'bg-blue-600 text-white hover:bg-blue-500' : ''}`} title="Tìm kiếm">
               <Search size={24} />
           </button>
           {isSearchOpen && (
               <div className="bg-white/95 backdrop-blur-sm p-4 rounded-xl shadow-2xl border border-gray-200 w-80 animate-in slide-in-from-left-4 duration-200">
                   <form onSubmit={handleSearch} className="flex gap-2">
                       <input className="flex-1 bg-gray-100 border border-gray-300 rounded px-3 py-2 text-sm outline-none focus:border-blue-500" placeholder="Số tờ, số thửa, tên..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} autoFocus />
                       <button type="submit" className="bg-blue-600 text-white p-2 rounded hover:bg-blue-500">
                           {isSearching ? <Loader2 size={16} className="animate-spin"/> : <Search size={16} />}
                       </button>
                   </form>
                   <div className="mt-4 max-h-60 overflow-y-auto custom-scrollbar space-y-2">
                       {searchResults.map(parcel => (
                           <div key={parcel.id} onClick={() => handleSelectSearchResult(parcel)} className="p-3 rounded bg-gray-50 hover:bg-blue-50 border border-gray-100 cursor-pointer transition-colors group">
                               <div className="font-bold text-gray-800 text-sm">Tờ: {parcel.properties['so_to']||'?'} - Thửa: {parcel.properties['so_thua']||'?'}</div>
                               <div className="text-xs text-gray-500 mt-1 truncate">Chủ: {parcel.properties.ownerName}</div>
                           </div>
                       ))}
                       {searchResults.length === 0 && !isSearching && searchQuery && <div className="text-center text-gray-400 text-sm py-4 italic">Không có kết quả.</div>}
                   </div>
               </div>
           )}
      </div>

      {/* Layer Control */}
      <div className="absolute top-4 right-4 z-[400] flex flex-col items-end gap-2">
          <button className={`p-3 bg-white rounded-lg shadow-lg hover:bg-gray-50 text-gray-700 transition-all ${isLayerMenuOpen ? 'bg-blue-50 text-blue-600 ring-2 ring-blue-300' : ''}`} onClick={() => setIsLayerMenuOpen(!isLayerMenuOpen)}>
              <Layers size={24} />
          </button>
          {isLayerMenuOpen && (
              <div className="bg-white/95 backdrop-blur-sm p-4 rounded-xl shadow-2xl border border-gray-200 w-72 animate-in slide-in-from-right-10 duration-200">
                  <h4 className="text-xs font-bold text-gray-500 uppercase mb-3 tracking-wider">Nền Bản đồ</h4>
                  <div className="space-y-2 mb-4">
                      {['OSM', 'GOOGLE', 'VIETBANDO'].map((type: any) => (
                          <div key={type} onClick={() => setActiveBaseLayer(type)} className={`flex items-center gap-3 p-2 rounded cursor-pointer transition-colors ${activeBaseLayer === type ? 'bg-blue-50 border border-blue-200' : 'hover:bg-gray-100 border border-transparent'}`}>
                              <div className={`w-4 h-4 rounded-full border flex items-center justify-center ${activeBaseLayer === type ? 'border-blue-600' : 'border-gray-400'}`}>{activeBaseLayer === type && <div className="w-2 h-2 bg-blue-600 rounded-full" />}</div>
                              <span className="text-sm font-medium text-gray-700">{type}</span>
                          </div>
                      ))}
