export const gisService = {
    getLayers: async (): Promise<WMSLayerConfig[]> => {
        try {
            return await apiCall('/api/wms-layers');
        } catch (e) {
            console.warn("Could not fetch WMS layers", e);
            return [];
        }
    },
    getSpatialTables: async (): Promise<string[]> => {
        try {
            return await apiCall('/api/spatial-tables');
        } catch (e) {
            return [];
        }
    },
    // --- ADVANCED SEARCH IMPLEMENTATION ---
    searchParcels: async (tableName: string, filters: { sodoto?: string, sothua?: string, tenchu?: string, diachi?: string }): Promise<LandParcel[]> => {
        try {
             // Use Server-side filtering to ensure exact matches for numbers and prevent loading large datasets
             let queryString = `?t=${Date.now()}`;
             if (filters.sodoto) queryString += `&sodoto=${encodeURIComponent(filters.sodoto)}`;
             if (filters.sothua) queryString += `&sothua=${encodeURIComponent(filters.sothua)}`;
             if (filters.tenchu) queryString += `&tenchu=${encodeURIComponent(filters.tenchu)}`;
             if (filters.diachi) queryString += `&diachi=${encodeURIComponent(filters.diachi)}`;

             const data = await apiCall(`/api/${tableName}${queryString}`);

             // Map to LandParcel type
             return data.map((item: any) => ({
                 id: item.gid?.toString() || `p-${Math.random()}`,
                 geometry: item.geometry,
                 properties: {
                     ...item,
                     // Ensure critical fields for Map Display
                     so_to: item.sodoto,
                     so_thua: item.sothua,
                     ownerName: item.tenchu,
                     address: item.diachi,
                     area: item.dientich,
                     landType: (item.properties && item.properties.landType) || 'Residential', // Default or from JSONB
                     tableName: tableName
                 }
             })).slice(0, 50); // Limit results to 50 for UI performance
        } catch (e) {
            console.error("Search error:", e);
            return [];
        }
    }
};

export const statsService = {
    getDashboardStats: async (currentUser: User): Promise<DashboardStats> => {
        try {
            // 1. Get all tables to aggregate data
            const tables = await apiCall('/api/spatial-tables');
            const tablesToFetch = tables.length > 0 ? tables : ['parcels'];

            let allParcels: any[] = [];

            // 2. Fetch data from all tables (limit 5000 per table to avoid crash)
            // Note: In production, this should be a dedicated aggregation API endpoint
            for (const table of tablesToFetch) {
                try {
                    const data = await apiCall(`/api/${table}?limit=5000`);
                    allParcels = [...allParcels, ...data];
                } catch (e) { console.warn(`Skipping stats for table ${table}`); }
            }

            // 3. Filter by branch if not ADMIN (Simple logic: if user belongs to branch, only show their data?)
            // Currently data doesn't have branch_id column explicitly, assuming all accessible or filtered by logic
            // For now, ADMIN sees all.
            const filtered = allParcels;

            const totalParcels = filtered.length;
            const totalArea = filtered.reduce((sum: number, p: any) => sum + (Number(p.dientich) || 0), 0);

            // 4. Calculate Types (Mocking logic based on random property or keyword in address if not present)
            // Trying to find 'loaidat' or 'landType' in properties
            const typeCounts: Record<string, number> = {
                'Đất ở (ONT/ODT)': 0,
                'Đất Nông nghiệp (CLN)': 0,
                'Đất Sản xuất (SKC)': 0,
                'Đất Công cộng': 0
            };

            filtered.forEach((p: any) => {
                const props = p.properties || {};
                const type = (props.loaidat || props.landType || '').toUpperCase();

                if (type.includes('ONT') || type.includes('ODT') || type.includes('THO')) typeCounts['Đất ở (ONT/ODT)']++;
                else if (type.includes('CLN') || type.includes('LUA') || type.includes('RSX')) typeCounts['Đất Nông nghiệp (CLN)']++;
                else if (type.includes('SKC') || type.includes('TMD')) typeCounts['Đất Sản xuất (SKC)']++;
                else typeCounts['Đất Công cộng']++; // Fallback
            });

            // 5. Estimated Value (Mock calculation: Area * Avg Price)
            // Residential ~ 10tr/m2, Agri ~ 2tr/m2
            let totalValue = 0;
            filtered.forEach((p: any) => {
                const area = Number(p.dientich) || 0;
                const props = p.properties || {};
                const type = (props.loaidat || props.landType || '').toUpperCase();

                let price = 2000000; // Default 2tr
                if (type.includes('ONT') || type.includes('ODT')) price = 10000000;
                else if (type.includes('SKC')) price = 5000000;

                totalValue += area *QB price;
            });

            return {
                totalParcels,
                totalArea,
                totalValue,
                parcelsByType: Object.keys(typeCounts).map(key => ({ name: key, value: typeCounts[key] })).filter(x => x.value > 0),
                // Mock Branch Distribution based on Table Names or Address
                valueByBranch: tablesToFetch.map(t => ({ 
