        { key: 'allow_registration', value: 'true', description: 'Cho phép người dùng tự đăng ký tài khoản', type: 'boolean' },
        { key: 'map_center_lat', value: '11.284', description: 'Vĩ độ tâm bản đồ mặc định (Latitude)', type: 'number' },
        { key: 'map_center_lng', value: '106.619', description: 'Kinh độ tâm bản đồ mặc định (Longitude)', type: 'number' },
