                             <div className="text-xl font-bold text-gray-800">{formData.so_to || '?'}</div>
                         </div>
                         <div className="flex-1 bg-blue-50 border border-blue-100 rounded-lg p-2 text-center">
                             <div className="text-[10px] text-blue-500 font-bold uppercase tracking-wider">Số thửa</div>
                             <div className="text-xl font-bold text-gray-800">{formData.so_thua || '?'}</div>
                         </div>
                     </div>

                     <div className="space-y-3">
