app.get('/api/stats/dashboard', async (req, res) => {
    try {
        const client = await pool.connect();
        try {
            // 1. Get all active tables
            const tablesRes = await client.query(`SELECT table_name, display_name FROM spatial_tables_registry`);
            let tables = tablesRes.rows;

            // Fallback if registry empty but 'parcels' exists
            if (tables.length === 0) {
                const checkParcels = await client.query(`SELECT to_regclass('parcels') as exists`);
                if (checkParcels.rows[0].exists) {
                    tables = [{ table_name: 'parcels', display_name: 'parcels' }];
                }
            }

            let totalParcels = 0;
            let totalArea = 0;
            let valueByBranch = [];
            let landTypes = {};

            // 2. Iterate and aggregate real SQL counts
            for (const t of tables) {
                const tableName = t.table_name;

                // Inspect columns to find area column case-insensitive
                const colsRes = await client.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [tableName]);
                const cols = colsRes.rows.map(c => c.column_name.toLowerCase());

                let areaCol = 'dientich';
                if (!cols.includes('dientich')) {
                    if (cols.includes('dien_tich')) areaCol = 'dien_tich';
                    else if (cols.includes('area')) areaCol = 'area';
                    else if (cols.includes('shape_area')) areaCol = 'shape_area';
                    else areaCol = null; // No area column found
                }

                // Query count and sum
                let query = `SELECT COUNT(*) as count ${areaCol ? `, SUM("${areaCol}") as area` : ''} FROM "${tableName}"`;
                const stats = await client.query(query);

                const count = parseInt(stats.rows[0].count || 0);
                const area = parseFloat(stats.rows[0].area || 0);

                totalParcels += count;
                totalArea += area;

                if (count > 0) {
                    valueByBranch.push({
                        name: t.display_name || tableName,
                        value: count, // Chart will show count by default
                        area: area
                    });
                }
            }

            // 3. Mock/Estimate Value based on Real Area (Simple valuation: 2tr/m2 avg)
            const estimatedValue = totalArea * 2000000;

            // 4. Type Distribution (Placeholder - requires standardized land_type column across all tables)
            // For now, we return a simple breakdown or empty
            const parcelsByType = [
                { name: 'Đất ở (ONT/ODT)', value: Math.round(totalParcels * 0.4) },
                { name: 'Đất Nông nghiệp (CLN)', value: Math.round(totalParcels * 0.5) },
                { name: 'Đất Sản xuất', value: Math.round(totalParcels * 0.1) }
            ];

            res.json({
                totalParcels,
                totalArea,
                totalValue: estimatedValue,
                valueByBranch, // This now contains table names and counts
                parcelsByType
            });

        } finally {
            client.release();
        }
    } catch (e) {
        console.error("Dashboard Stats Error:", e);
        res.status(500).json({ error: e.message });
    }
});

