app.post('/api/:tableName/upload', upload.single('file'), async (req, res) => {
    try {
        const { tableName } = req.params;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '');
        const file = req.file;

        if (!file) return res.status(400).json({error: "No file uploaded"});
        if (!file.originalname.endsWith('.zip')) return res.status(400).json({error: "Only .zip files are allowed"});

        const geojson = await shp(file.buffer);
        const features = Array.isArray(geojson) ? geojson[0].features : geojson.features;

        const client = await pool.connect();
        try {
            await client.query('BEGIN');
            for (const f of features) {
                const props = f.properties || {};
                const geom = f.geometry;

                const sothua = props.SoThua || props.ShThua || props.SOTHUA || props.shthua || '0';
                const sodoto = props.SoTo || props.ShMap || props.SOTO || props.shmap || '0';
                const tenchu = props.TenChu || props.ChuSoHuu || props.TENCHU || 'Unknown';
                const diachi = props.DiaChi || props.DIACHI || '';
                const dientich = props.DienTich || props.DIENTICH || 0;

                // --- FIX: ASSUME UPLOAD IS VN-2000 (9210) ---
                // We set input SRID to 9210, then transform to 4326 to match database standard (if table is 4326)
                // or just to have standard data for web.
                await client.query(`
                    INSERT INTO "${safeName}" (sothua, sodoto, tenchu, diachi, dientich, geometry, properties)
                    VALUES ($1, $2, $3, $4, $5, ST_Transform(ST_SetSRID(ST_GeomFromGeoJSON($6), 9210), 4326), $7)
                `, [sothua, sodoto, tenchu, diachi, dientich, JSON.stringify(geom), JSON.stringify(props)]);
            }
            await client.query('COMMIT');
            await logSystemAction(req, 'UPLOAD_SHAPEFILE', `Upload Shapefile vào bảng ${safeName} (${features.length} đối tượng)`);
            res.json({status: 'ok', count: features.length});
        } catch (e) {
            await client.query('ROLLBACK');
            throw e;
        } finally {
            client.release();
        }
    } catch(e) { res.status(500).json({error: e.message}); }
});

