export default MapPage;

import React, { useEffect, useState } from 'react';
import { parcelApi, ParcelDTO, SpatialTable } from '../services/parcelApi';
import { Edit, Trash2, Plus, Save, X, RefreshCw, Layers, Search, MapPin, Database, User, FileUp, Home, Filter, AlertTriangle } from 'lucide-react';

const ParcelManager: React.FC = () => {
    // Config State
    const [layer, setLayer] = useState('');
    const [availableTables, setAvailableTables] = useState<SpatialTable[]>([]);

    // Data State
    const [parcels, setParcels] = useState<ParcelDTO[]>([]);
    // Removed client-side filteredParcels state as we now filter on server
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Search/Filter State
    const [searchFilters, setSearchFilters] = useState({
        sodoto: '',
        sothua: '',
        tenchu: '',
        diachi: ''
    });

    // Form State
    const [formData, setFormData] = useState<ParcelDTO>({ sothua: '', sodoto: '', tenchu: '', diachi: '', file: null });
    const [editingId, setEditingId] = useState<number | null>(null);

    useEffect(() => {
        loadTables();
    }, []);

    // Removed auto-load useEffect on layer change to prevent lag
    // useEffect(() => { if (layer) loadParcels(); }, [layer]);

    const loadTables = async () => {
        try {
            const tables = await parcelApi.manageTables.getAll();
            setAvailableTables(tables);
            if (tables.length > 0) setLayer(tables[0].table_name);
        } catch (e) {
            setAvailableTables([]);
            setLayer('');
        }
    };

    const loadParcels = async () => {
        if (!layer) return;
        setLoading(true);
        setError(null);
        try {
            // Trim inputs before sending to server for exact match
            const cleanedFilters = {
                sodoto: searchFilters.sodoto.trim(),
                sothua: searchFilters.sothua.trim(),
                tenchu: searchFilters.tenchu.trim(),
                diachi: searchFilters.diachi.trim()
            };

            // Send search filters to backend
            const data = await parcelApi.getAll(layer, cleanedFilters);
            setParcels(data.sort((a: any, b: any) => b.gid - a.gid));
        } catch (err: any) {
            setError(err.message);
            setParcels([]); 
        } finally {
            setLoading(false);
        }
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            setFormData({ ...formData, file: e.target.files[0] });
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.sothua || !formData.sodoto) {
            alert("Vui lòng nhập đầy đủ Số tờ và Số thửa");
            return;
        }

        try {
            if (editingId) {
                if (formData.file) {
                    await parcelApi.updateWithUpload(layer, editingId, formData);
                    alert("Cập nhật thành công! Hình học và Diện tích mới đã được lưu.");
                } else {
                    await parcelApi.update(layer, editingId, formData);
                    alert("Cập nhật thông tin thuộc tính thành công!");
                }
            } else {
                if (formData.file) {
                    await parcelApi.createWithUpload(layer, formData);
                    alert("Upload Shapefile và thêm mới thành công! Diện tích đã được tự động tính.");
                } else {
                    await parcelApi.create(layer, formData);
                    alert("Thêm mới thành công (Không có hình học).");
                }
            }
            resetForm();
            loadParcels(); // Refresh list after edit
        } catch (err: any) {
            alert("Lỗi thao tác: " + err.message);
        }
    };

    const handleEdit = (parcel: ParcelDTO) => {
        setEditingId(parcel.gid!);
        setFormData({
            sothua: parcel.sothua,
            sodoto: parcel.sodoto,
            tenchu: parcel.tenchu || '',
            diachi: parcel.diachi || '',
            file: null 
        });

        const fileInput = document.getElementById('file-upload') as HTMLInputElement;
        if (fileInput) fileInput.value = '';

        const formElement = document.getElementById('parcel-form');
        if (formElement) formElement.scrollIntoView({ behavior: 'smooth' });
    };

    const handleDelete = async (gid: number) => {
        if (!confirm(`CẢNH BÁO: Bạn có chắc chắn muốn xóa thửa đất có GID: ${gid}? Hành động này không thể hoàn tác.`)) return;
        try {
            await parcelApi.delete(layer, gid);
            setParcels(prev => prev.filter(p => p.gid !== gid));
        } catch (err: any) {
            alert("Lỗi xóa: " + err.message);
            loadParcels(); 
        }
    };

    const resetForm = () => {
        setEditingId(null);
        setFormData({ sothua: '', sodoto: '', tenchu: '', diachi: '', file: null });
        const fileInput = document.getElementById('file-upload') as HTMLInputElement;
        if (fileInput) fileInput.value = '';
    };

    const clearFilters = () => {
        setSearchFilters({ sodoto: '', sothua: '', tenchu: '', diachi: '' });
        setParcels([]); // Clear results on clear filter
    };

    const handleSearchClick = () => {
        loadParcels();
    };

    return (
        <div className="p-6 bg-gray-900 text-white min-h-full">
            {/* HEADER */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4 border-b border-gray-800 pb-6">
                <div>
                    <h2 className="text-2xl font-bold flex items-center gap-2 text-white">
                        <Database className="text-blue-500" />
                        Quản lý Dữ liệu Thửa đất
                    </h2>
                    <p className="text-gray-400 text-sm mt-1">Quản lý thuộc tính và không gian (Spatial Data)</p>
                </div>

                <div className="flex items-center gap-3 bg-gray-800 p-3 rounded-lg border border-gray-700 shadow-sm">
                    <div className="flex items-center gap-2 text-blue-400">
                        <Layers size={18} />
                        <span className="text-sm font-semibold uppercase">Lớp dữ liệu:</span>
                    </div>
                    {availableTables.length > 0 ? (
                        <select 
                            value={layer} 
                            onChange={(e) => setLayer(e.target.value)}
                            className="bg-gray-900 text-white border border-gray-600 rounded px-3 py-1.5 text-sm outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-all cursor-pointer"
                        >
                            {availableTables.map(tbl => (
                                <option key={tbl.table_name} value={tbl.table_name}>{tbl.display_name || tbl.table_name}</option>
                            ))}
                        </select>
                    ) : (
                        <span className="text-sm text-red-400 italic">Chưa có bảng dữ liệu</span>
                    )}
                </div>
            </div>

            {/* Error Alert */}
            {error && (
                <div className="mb-6 bg-red-900/20 border border-red-500 text-red-200 p-4 rounded-lg flex items-center justify-between animate-in fade-in slide-in-from-top-2">
                    <div className="flex items-center gap-3">
                        <AlertTriangle className="text-red-500" size={24} />
                        <div>
                            <h4 className="font-bold">Lỗi tải dữ liệu</h4>
                            <p className="text-sm opacity-80">{error}</p>
                        </div>
                    </div>
                    <button onClick={() => { setError(null); loadParcels(); }} className="px-3 py-1 bg-red-700 hover:bg-red-600 rounded text-sm font-bold text-white transition-colors">
                        Thử lại
                    </button>
                </div>
            )}

            {/* ADVANCED SEARCH PANEL */}
            <div className="bg-gray-800 p-5 rounded-xl border border-gray-700 shadow-lg mb-6">
                <div className="flex items-center justify-between mb-4">
                    <h4 className="text-sm font-bold text-gray-400 uppercase flex items-center gap-2">
                        <Filter size={16} /> Tìm kiếm & Lọc dữ liệu
                    </h4>
                    {(searchFilters.sodoto || searchFilters.sothua || searchFilters.tenchu || searchFilters.diachi) && (
                        <button onClick={clearFilters} className="text-xs text-red-400 hover:text-red-300 flex items-center gap-1">
                            <X size={12} /> Xóa bộ lọc
                        </button>
                    )}
                </div>
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-4">
                    <div className="relative">
                         <input 
                            type="text" 
                            className="w-full bg-gray-900 border border-gray-600 rounded px-3 py-2 text-sm text-white focus:border-blue-500 outline-none pl-9"
                            placeholder="Số tờ..." 
                            value={searchFilters.sodoto}
                            onChange={(e) => setSearchFilters({...searchFilters, sodoto: e.target.value})}
                         />
                         <Search className="absolute left-3 top-2.5 text-gray-500" size={14} />
                    </div>
                    <div className="relative">
                         <input 
                            type="text" 
                            className="w-full bg-gray-900 border border-gray-600 rounded px-3 py-2 text-sm text-white focus:border-blue-500 outline-none pl-9"
                            placeholder="Số thửa..." 
                            value={searchFilters.sothua}
                            onChange={(e) => setSearchFilters({...searchFilters, sothua: e.target.value})}
                         />
                         <MapPin className="absolute left-3 top-2.5 text-gray-500" size={14} />
                    </div>
                    <div className="relative">
                         <input 
                            type="text" 
                            className="w-full bg-gray-900 border border-gray-600 rounded px-3 py-2 text-sm text-white focus:border-blue-500 outline-none pl-9"
                            placeholder="Tên chủ sở hữu..." 
                            value={searchFilters.tenchu}
                            onChange={(e) => setSearchFilters({...searchFilters, tenchu: e.target.value})}
                         />
                         <User className="absolute left-3 top-2.5 text-gray-500" size={14} />
                    </div>
                    <div className="relative">
                         <input 
                            type="text" 
                            className="w-full bg-gray-900 border border-gray-600 rounded px-3 py-2 text-sm text-white focus:border-blue-500 outline-none pl-9"
                            placeholder="Địa chỉ..." 
                            value={searchFilters.diachi}
                            onChange={(e) => setSearchFilters({...searchFilters, diachi: e.target.value})}
                         />
                         <Home className="absolute left-3 top-2.5 text-gray-500" size={14} />
                    </div>
                </div>
                <button 
                    onClick={handleSearchClick}
                    className="w-full bg-blue-600 hover:bg-blue-500 text-white py-2 rounded font-bold flex items-center justify-center gap-2 transition-all active:scale-95"
                >
                    {loading ? <RefreshCw className="animate-spin" size={18} /> : <Search size={18} />}
                    Tìm kiếm Dữ liệu
                </button>
            </div>

            {/* INPUT FORM SECTION */}
            <div id="parcel-form" className={`bg-gray-800 p-6 rounded-xl border ${editingId ? 'border-orange-500/50 ring-1 ring-orange-500/30' : 'border-gray-700'} shadow-lg mb-8 transition-all`}>
                <h3 className={`text-lg font-bold mb-4 flex items-center gap-2 ${editingId ? 'text-orange-400' : 'text-blue-400'}`}>
                    {editingId ? <Edit size={20}/> : <Plus size={20}/>}
                    {editingId ? `Cập nhật Thửa đất (GID: ${editingId})` : 'Thêm Thửa đất Mới'}
                </h3>

                <form onSubmit={handleSubmit} className="flex flex-col gap-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {/* Số Tờ */}
                        <div>
                            <label className="block text-xs font-bold text-gray-500 uppercase mb-1 tracking-wider">Số Tờ bản đồ</label>
                            <div className="relative">
                                <MapPin className="absolute left-3 top-2.5 text-gray-500" size={16} />
                                <input type="text" className="w-full bg-gray-900 border border-gray-600 rounded-lg pl-10 pr-3 py-2 text-white focus:border-blue-500 outline-none"
                                    placeholder="Ví dụ: 15" value={formData.sodoto} onChange={e => setFormData({...formData, sodoto: e.target.value})} required
                                />
                            </div>
                        </div>
                        {/* Số Thửa */}
                        <div>
                            <label className="block text-xs font-bold text-gray-500 uppercase mb-1 tracking-wider">Số hiệu Thửa</label>
                            <div className="relative">
                                <MapPin className="absolute left-3 top-2.5 text-gray-500" size={16} />
                                <input type="text" className="w-full bg-gray-900 border border-gray-600 rounded-lg pl-10 pr-3 py-2 text-white focus:border-blue-500 outline-none"
                                    placeholder="Ví dụ: 102" value={formData.sothua} onChange={e => setFormData({...formData, sothua: e.target.value})} required
                                />
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {/* Tên Chủ */}
                        <div>
                            <label className="block text-xs font-bold text-gray-500 uppercase mb-1 tracking-wider">Tên Chủ sở hữu</label>
                            <div className="relative">
                                <User className="absolute left-3 top-2.5 text-gray-500" size={16} />
                                <input type="text" className="w-full bg-gray-900 border border-gray-600 rounded-lg pl-10 pr-3 py-2 text-white focus:border-blue-500 outline-none"
                                    placeholder="Nguyễn Văn A" value={formData.tenchu||''} onChange={e => setFormData({...formData, tenchu: e.target.value})}
                                />
                            </div>
                        </div>
                        {/* Địa chỉ */}
                        <div>
                            <label className="block text-xs font-bold text-gray-500 uppercase mb-1 tracking-wider">Địa chỉ</label>
                            <div className="relative">
                                <Home className="absolute left-3 top-2.5 text-gray-500" size={16} />
                                <input type="text" className="w-full bg-gray-900 border border-gray-600 rounded-lg pl-10 pr-3 py-2 text-white focus:border-blue-500 outline-none"
                                    placeholder="Xã Lai Uyên, Bàu Bàng..." value={formData.diachi||''} onChange={e => setFormData({...formData, diachi: e.target.value})}
                                />
                            </div>
                        </div>
                    </div>

                    {/* Upload File - Always visible now */}
                    <div className="bg-gray-700/30 p-4 rounded-lg border border-dashed border-gray-600">
                         <label className="block text-xs font-bold text-gray-400 uppercase mb-2 tracking-wider flex items-center gap-2">
                            <FileUp size={16} /> 
                            {editingId ? 'Cập nhật Shapefile (Tùy chọn)' : 'Upload Shapefile (.zip)'}
                            <span className="text-[10px] normal-case bg-blue-900 text-blue-200 px-2 rounded-full">
                                {editingId ? 'Thay thế hình học & Tính lại diện tích' : 'Tự động tính diện tích'}
                            </span>
                         </label>
                         <input 
                            id="file-upload"
                            type="file" 
                            accept=".zip"
                            onChange={handleFileChange}
                            className="block w-full text-sm text-gray-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-600 file:text-white hover:file:bg-blue-500 cursor-pointer"
                         />
                    </div>

                    <div className="flex gap-3 justify-end mt-2">
                        {editingId && (
                            <button type="button" onClick={resetForm} className="bg-gray-700 hover:bg-gray-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors">
                                <X size={18} /> Hủy
                            </button>
                        )}
                        <button type="submit" className={`px-6 py-2 rounded-lg flex items-center justify-center gap-2 font-bold text-white shadow-lg transition-all ${editingId ? 'bg-orange-600 hover:bg-orange-500' : 'bg-blue-600 hover:bg-blue-500'}`}>
                            {editingId ? <Save size={18} /> : <Plus size={18} />}
                            {editingId ? 'Lưu thay đổi' : 'Thêm mới'}
                        </button>
                    </div>
                </form>
            </div>

            {/* DATA TABLE */}
            <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden shadow-xl">
                {/* Table Header */}
                <div className="grid grid-cols-12 bg-gray-900 text-gray-400 text-xs uppercase font-bold py-3 px-4 border-b border-gray-700 tracking-wider">
                    <div className="col-span-1">GID</div>
                    <div className="col-span-2">Số Tờ</div>
                    <div className="col-span-2">Số Thửa</div>
                    <div className="col-span-3">Chủ sở hữu</div>
                    <div className="col-span-2 text-right">Diện tích (m²)</div>
                    <div className="col-span-2 text-right">Thao tác</div>
                </div>

                {/* Table Body */}
                {loading ? (
                    <div className="p-12 flex justify-center items-center text-blue-400 flex-col gap-3">
                        <RefreshCw className="animate-spin w-8 h-8"/>
                        <span>Đang truy vấn dữ liệu từ máy chủ...</span>
                    </div>
                ) : parcels.length === 0 ? (
                    <div className="p-16 text-center text-gray-500 flex flex-col items-center gap-3">
                        <Search size={48} className="text-gray-700" />
                        <p className="font-medium">Chưa có dữ liệu hiển thị</p>
                        <p className="text-sm">Vui lòng nhập thông tin tìm kiếm hoặc nhấn nút "Tìm kiếm Dữ liệu" để tải danh sách.</p>
                    </div>
                ) : (
                    <div className="max-h-[600px] overflow-y-auto custom-scrollbar">
                        {parcels.map((p) => (
                            <div key={p.gid} className={`grid grid-cols-12 py-3 px-4 items-center border-b border-gray-700/50 hover:bg-gray-700/50 transition-colors group ${editingId === p.gid ? 'bg-orange-900/20 border-l-4 border-orange-500 pl-3' : ''}`}>
                                <div className="col-span-1 font-mono text-xs text-gray-500">#{p.gid}</div>
                                <div className="col-span-2 font-bold text-white">{p.sodoto || '--'}</div>
                                <div className="col-span-2 font-bold text-blue-400">{p.sothua || '--'}</div>
                                <div className="col-span-3 text-gray-300 truncate pr-2">{p.tenchu || '--'}</div>
                                <div className="col-span-2 text-right font-mono text-green-400">
                                    {p.dientich ? Math.round(Number(p.dientich)).toLocaleString() : '--'}
                                </div>
                                <div className="col-span-2 text-right flex justify-end gap-2 opacity-60 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => handleEdit(p)} className="bg-blue-600/20 text-blue-400 hover:bg-blue-600 hover:text-white p-1.5 rounded transition-colors"><Edit size={16} /></button>
                                    <button onClick={() => handleDelete(p.gid!)} className="bg-red-600/20 text-red-400 hover:bg-red-600 hover:text-white p-1.5 rounded transition-colors"><Trash2 size={16} /></button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
};

export default ParcelManager;

