    // --- ADVANCED SEARCH IMPLEMENTATION ---
    searchParcels: async (tableName: string, filters: { sodoto?: string, sothua?: string, tenchu?: string, diachi?: string }): Promise<LandParcel[]> => {
        try {
             // Use Server-side filtering to ensure exact matches for numbers and prevent loading large datasets
             let queryString = `?t=${Date.now()}`;
             if (filters.sodoto) queryString += `&sodoto=${encodeURIComponent(filters.sodoto)}`;
             if (filters.sothua) queryString += `&sothua=${encodeURIComponent(filters.sothua)}`;
             if (filters.tenchu) queryString += `&tenchu=${encodeURIComponent(filters.tenchu)}`;
             if (filters.diachi) queryString += `&diachi=${encodeURIComponent(filters.diachi)}`;

             const data = await apiCall(`/api/${tableName}${queryString}`);

             // Map to LandParcel type
             return data.map((item: any) => ({
                 id: item.gid?.toString() || `p-${Math.random()}`,
                 geometry: item.geometry,
                 properties: {
                     ...item,
                     // Ensure critical fields for Map Display
                     so_to: item.sodoto,
                     so_thua: item.sothua,
                     ownerName: item.tenchu,
                     address: item.diachi,
                     area: item.dientich,
                     landType: (item.properties && item.properties.landType) || 'Residential', // Default or from JSONB
                     tableName: tableName
                 }
             })).slice(0, 50); // Limit results to 50 for UI performance
        } catch (e) {
            console.error("Search error:", e);
            return [];
        }
    }
};

