import dbConfig from './db_config.js';
import os from 'os';         // System info

const { Pool } = pg;

const app = express();
const port = 3004;

// --- FIX: Trust Proxy (Required behind Nginx/Cloudflare) ---
app.enable('trust proxy');

// --- FIX CORS: Robust Configuration ---
const allowedOrigins = [
    'https://geo.gisvn.space', 
    'https://www.geo.gisvn.space', 
    'https://apigeo.gisvn.space', 
    'http://localhost:3003',
    'http://localhost:5173',
    'http://127.0.0.1:3003',
    'http://127.0.0.1:5173'
];

const corsOptions = {
    origin: function (origin, callback) {
        // Allow requests with no origin (like mobile apps or curl requests)
        if (!origin) return callback(null, true);

        if (allowedOrigins.indexOf(origin) !== -1) {
            callback(null, true);
        } else {
            // Allow mostly everything for development stability
            callback(null, true);
        }
    },
    credentials: true, // Allow cookies/auth headers
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS', 'PATCH'],
    allowedHeaders: ['Content-Type', 'Authorization', 'x-user-id', 'x-user-name', 'x-branch-id', 'X-Requested-With', 'Accept', 'Origin'],
    exposedHeaders: ['Content-Range', 'X-Content-Range'],
    optionsSuccessStatus: 200
};

app.use(cors(corsOptions));
// Tăng giới hạn payload để hỗ trợ upload ảnh base64 qua JSON
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ limit: '10mb', extended: true }));

// Multer memory storage
const upload = multer({ storage: multer.memoryStorage() });

const pool = new Pool(dbConfig);

// ----------------------------------------------------
