            // 5. System Logs
            await client.query(`
                CREATE TABLE IF NOT EXISTS system_logs (
                    id SERIAL PRIMARY KEY,
                    user_id VARCHAR(50),
                    user_name VARCHAR(100),
                    action VARCHAR(50),
                    details TEXT,
                    timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    branch_id VARCHAR(50)
                )
            `);

            // --- FIX FOR MISSING SERIAL/SEQUENCE ON EXISTING SYSTEM_LOGS TABLE ---
            try {
                const logSeqCheck = await client.query(`SELECT column_default FROM information_schema.columns WHERE table_name = 'system_logs' AND column_name = 'id'`);
                if (logSeqCheck.rows.length > 0 && !logSeqCheck.rows[0].column_default) {
                    console.log("🔧 Fixing missing sequence for system_logs.id...");
                    await client.query(`CREATE SEQUENCE IF NOT EXISTS system_logs_id_seq`);
                    await client.query(`ALTER TABLE system_logs ALTER COLUMN id SET DEFAULT nextval('system_logs_id_seq')`);
                    await client.query(`SELECT setval('system_logs_id_seq', COALESCE((SELECT MAX(id) FROM system_logs), 0) + 1)`);
                    console.log("✅ Fixed system_logs sequence.");
                }
            } catch (e) {
                console.warn("⚠️ Could not auto-fix system_logs sequence:", e.message);
            }

             // 6. Land Prices
             await client.query(`
                CREATE TABLE IF NOT EXISTS land_prices (
                    land_type VARCHAR(50) PRIMARY KEY,
                    base_price NUMERIC,
                    description TEXT
                )
            `);
            // --- FIX: Ensure description column exists (migration for existing DBs) ---
            try {
                await client.query(`ALTER TABLE land_prices ADD COLUMN IF NOT EXISTS description TEXT`);
            } catch (e) { /* ignore */ }

            // 7. WMS Layers
            await client.query(`
                CREATE TABLE IF NOT EXISTS wms_layers (
                    id VARCHAR(50) PRIMARY KEY,
                    name VARCHAR(100),
                    url TEXT,
                    layers VARCHAR(100),
                    visible BOOLEAN DEFAULT true
                )
            `);

            // 8. Role Permissions
            await client.query(`
                CREATE TABLE IF NOT EXISTS role_permissions (
                    role VARCHAR(20) PRIMARY KEY,
                    permissions JSONB
                )
            `);

            // --- SCHEMA FIXES & SEEDING (Role Permissions) ---
            try {
                // Remove duplicate roles
                await client.query(`DELETE FROM role_permissions a USING role_permissions b WHERE a.ctid < b.ctid AND a.role = b.role`);
                // Add Primary Key constraint if missing
                await client.query(`ALTER TABLE role_permissions ADD PRIMARY KEY (role)`);
            } catch (e) { /* Ignore if PK exists */ }

            // Seed Default Admin Permissions
            await client.query(`
                INSERT INTO role_permissions (role, permissions) 
                VALUES ('ADMIN', '["VIEW_MAP","EDIT_MAP","DELETE_MAP","VIEW_DASHBOARD","EXPORT_REPORT","MANAGE_USERS","MANAGE_SYSTEM","VIEW_LOGS","MANAGE_TABLES"]'::jsonb)
                ON CONFLICT (role) DO NOTHING
            `);            

            // 9. Spatial Tables Registry
            await client.query(`
                CREATE TABLE IF NOT EXISTS spatial_tables_registry (
                    table_name VARCHAR(100) PRIMARY KEY,
                    display_name VARCHAR(100),
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            `);
            console.log("✅ Database initialized: All system tables are ready.");
        } finally {
            client.release();
        }
    } catch (err) {
        console.error("⚠️ Database initialization warning:", err.message);
    }
};
