// 1. BACKUP DATABASE (pg_dump)
app.get('/api/system/backup', async (req, res) => {
    try {
        const date = new Date().toISOString().replace(/[:.]/g, '-');
        const filename = `backup-${dbConfig.database}-${date}.sql`;

        res.setHeader('Content-Disposition', `attachment; filename="${filename}"`);
        res.setHeader('Content-Type', 'application/sql');

        const env = { ...process.env, PGPASSWORD: dbConfig.password };

        // Spawn pg_dump process
        const dumpProcess = spawn('pg_dump', [
            '-h', dbConfig.host,
            '-p', String(dbConfig.port),
            '-U', dbConfig.user,
            '--clean',      // Clean (DROP) schema before creation
            '--if-exists',  // Use IF EXISTS when dropping
            '--no-owner',   // Skip ownership commands
            '--no-acl',     // Skip privilege commands
            dbConfig.database
        ], { env });

        dumpProcess.stdout.pipe(res);

        dumpProcess.stderr.on('data', (data) => {
            console.error(`pg_dump error: ${data}`);
        });

        dumpProcess.on('close', (code) => {
            if (code === 0) {
                console.log(`✅ Database backup completed: ${filename}`);
                logSystemAction(req, 'BACKUP_DB', 'Sao lưu cơ sở dữ liệu thành công');
            } else {
                console.error(`pg_dump exited with code ${code}`);
                // Cannot send error response if headers already sent
            }
        });

    } catch (e) {
        console.error("Backup Failed:", e);
        if (!res.headersSent) res.status(500).send("Backup failed");
    }
});

// 2. RESTORE DATABASE (psql)
app.post('/api/system/restore', upload.single('file'), async (req, res) => {
    try {
        const file = req.file;
        if (!file) return res.status(400).json({ error: "No file uploaded" });

        console.log(`Starting restore for ${file.originalname} (${file.size} bytes)...`);

        const env = { ...process.env, PGPASSWORD: dbConfig.password };

        // Spawn psql process
        const restoreProcess = spawn('psql', [
            '-h', dbConfig.host,
            '-p', String(dbConfig.port),
            '-U', dbConfig.user,
            '-d', dbConfig.database
        ], { env });

        // Pipe file buffer to psql stdin
        restoreProcess.stdin.write(file.buffer);
        restoreProcess.stdin.end();

        let errorOutput = '';

        restoreProcess.stderr.on('data', (data) => {
            errorOutput += data.toString();
        });

        restoreProcess.on('close', (code) => {
            if (code === 0) {
                console.log("✅ Database restore completed successfully.");
                logSystemAction(req, 'RESTORE_DB', `Phục hồi cơ sở dữ liệu từ file: ${file.originalname}`);
                res.json({ status: 'ok', message: 'Restore successful' });
            } else {
                console.error(`psql exited with code ${code}: ${errorOutput}`);
                res.status(500).json({ error: "Restore failed", details: errorOutput });
            }
        });

    } catch (e) {
        console.error("Restore Failed:", e);
        res.status(500).json({ error: e.message });
    }
});

