// 4. Rename Table (Or Display Name)
app.put('/api/spatial-tables/:tableName', async (req, res) => {
    const { tableName } = req.params;
    const { newName, displayName } = req.body;

    const oldSafeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '');
    const client = await pool.connect();

    try {
        await client.query('BEGIN');

        // Scenario 1: Rename the actual table (and update registry)
        if (newName && newName !== oldSafeName) {
            const newSafeName = newName.toLowerCase().replace(/[^a-z0-9_]/g, '');

            const checkOld = await client.query(`SELECT to_regclass($1) as exists`, [oldSafeName]);
            if (!checkOld.rows[0].exists) throw new Error(`Bảng '${oldSafeName}' không tồn tại.`);

            const checkNew = await client.query(`SELECT to_regclass($1) as exists`, [newSafeName]);
            if (checkNew.rows[0].exists) throw new Error(`Bảng '${newSafeName}' đã tồn tại.`);

            await client.query(`ALTER TABLE "${oldSafeName}" RENAME TO "${newSafeName}"`);
            await client.query(`UPDATE spatial_tables_registry SET table_name = $1 WHERE table_name = $2`, [newSafeName, oldSafeName]);

            // If displayName is NOT provided, we might want to update it to match new table name, OR keep it. 
            // Here we assume if displayName provided, update it too.
            if (displayName) {
                await client.query(`UPDATE spatial_tables_registry SET display_name = $1 WHERE table_name = $2`, [displayName, newSafeName]);
            }

            await logSystemAction(req, 'RENAME_TABLE', `Đổi tên bảng từ ${oldSafeName} sang ${newSafeName}`);
        } 
        // Scenario 2: Only update Display Name
        else if (displayName) {
             await client.query(`UPDATE spatial_tables_registry SET display_name = $1 WHERE table_name = $2`, [displayName, oldSafeName]);
             await logSystemAction(req, 'UPDATE_TABLE_INFO', `Cập nhật tên hiển thị bảng ${oldSafeName} thành "${displayName}"`);
        }

        await client.query('COMMIT');
        res.json({status: 'ok'});
    } catch (e) {
        await client.query('ROLLBACK');
        res.status(500).json({error: e.message});
    } finally {
        client.release();
    }
});

