import ParcelManager from './ParcelManager';

interface AdminPageProps {
    systemName?: string;
    logoUrl?: string;
}

const AdminPage: React.FC<AdminPageProps> = ({ systemName, logoUrl }) => {
    const [activeTab, setActiveTab] = useState('PARCEL_MANAGER'); 

