                       ))}
                       {searchResults.length === 0 && !isSearching && (searchForm.soTo || searchForm.soThua || searchForm.owner) && <div className="text-center text-gray-400 text-sm py-4 italic">Không có kết quả.</div>}
                   </div>
               </div>
           )}
      </div>

      {/* Layer Control */}
      <div className="absolute top-4 right-4 z-[400] flex flex-col items-end gap-2">
          <button className={`p-3 bg-white rounded-lg shadow-lg hover:bg-gray-50 text-gray-700 transition-all ${isLayerMenuOpen ? 'bg-blue-50 text-blue-600 ring-2 ring-blue-300' : ''}`} onClick={() => setIsLayerMenuOpen(!isLayerMenuOpen)}>
              <Layers size={24} />
          </button>
          {isLayerMenuOpen && (
              <div className="bg-white/95 backdrop-blur-sm p-4 rounded-xl shadow-2xl border border-gray-200 w-72 animate-in slide-in-from-right-10 duration-200">
                  <h4 className="text-xs font-bold text-gray-500 uppercase mb-3 tracking-wider">Nền Bản đồ</h4>
                  <div className="space-y-2 mb-4">
                      {['OSM', 'GOOGLE', 'VIETBANDO'].map((type: any) => (
                          <div key={type} onClick={() => setActiveBaseLayer(type)} className={`flex items-center gap-3 p-2 rounded cursor-pointer transition-colors ${activeBaseLayer === type ? 'bg-blue-50 border border-blue-200' : 'hover:bg-gray-100 border border-transparent'}`}>
                              <div className={`w-4 h-4 rounded-full border flex items-center justify-center ${activeBaseLayer === type ? 'border-blue-600' : 'border-gray-400'}`}>{activeBaseLayer === type && <div className="w-2 h-2 bg-blue-600 rounded-full" />}</div>
                              <span className="text-sm font-medium text-gray-700">{type}</span>
                          </div>
                      ))}
                  </div>
                  <div className="border-t border-gray-100 my-3"></div>
                  <h4 className="text-xs font-bold text-gray-500 uppercase mb-3 tracking-wider flex justify-between items-center">
                      <span>Lớp Dữ liệu (WMS)</span>
                      <span className="text-[10px] text-blue-500 font-normal bg-blue-100 px-2 py-0.5 rounded">Chọn lớp để truy vấn</span>
                  </h4>
                  <div className="space-y-2">
                      {availableLayers.length === 0 ? <div className="text-xs text-gray-400 italic">Trống...</div> : availableLayers.map(l => {
                            const isActive = activeLayerId === l.id;
                            const isVisible = visibleLayerIds.includes(l.id);

                            return (
                                <div key={l.id} className={`flex items-center justify-between p-2 rounded transition-all cursor-pointer border ${isActive ? 'bg-blue-50 border-blue-200 ring-1 ring-blue-300' : 'hover:bg-gray-50 border-transparent'}`}>
                                    {/* CLICK NAME -> SET ACTIVE LAYER */}
                                    <div className="flex items-center gap-3 flex-1" onClick={() => handleSelectActiveLayer(l.id)}>
                                        <div className={`transition-colors ${isActive ? "text-blue-600" : "text-gray-400"}`}>
                                            {isActive ? <MousePointerClick size={18} className="animate-pulse" /> : <MapPin size={18} />}
                                        </div>
                                        <span className={`text-sm font-medium ${isActive ? 'text-blue-700' : 'text-gray-700'}`}>{l.name}</span>
                                    </div>
                                    {/* CLICK EYE -> TOGGLE VISIBILITY */}
                                    <button onClick={(e) => { e.stopPropagation(); toggleLayer(l.id); }} className={`text-gray-400 p-1 hover:bg-gray-200 rounded ${isVisible ? 'text-blue-600' : ''}`}>
                                        {isVisible ? <Eye size={18} /> : <EyeOff size={18} />}
                                    </button>
                                </div>
                            );
                      })}
                  </div>
              </div>
          )}
      </div>

      <div className="absolute bottom-24 right-4 z-[400]">
          <button onClick={handleLocateMe} className="p-3 bg-white rounded-lg shadow-lg hover:bg-gray-50 text-gray-700" title="Vị trí của tôi">
              {isLocating ? <Loader2 size={24} className="animate-spin text-blue-600"/> : <Crosshair size={24} />}
          </button>
      </div>

       {/* --- HIDDEN PRINT TEMPLATE --- */}
       <div className="absolute top-0 left-0 z-[-50]">
          <div ref={printTemplateRef} id="print-template" className="w-[210mm] bg-white py-[10mm] px-[15mm] flex flex-col items-center" style={{ fontFamily: '"Times New Roman", Times, serif', color: '#000000', backgroundColor: '#ffffff' }}>

              <div className="text-center mb-4">
                  <h3 className="font-bold text-lg uppercase" style={{color:'#000'}}>CỘNG HÒA XÃ HỘI CHỦ NGHĨA VIỆT NAM</h3>
                  <p className="font-bold text-sm underline underline-offset-4" style={{color:'#000'}}>Độc lập - Tự do - Hạnh phúc</p>
              </div>

              <h1 className="text-2xl font-bold uppercase mb-4 text-center" style={{color:'#000'}}>TRÍCH LỤC BẢN ĐỒ ĐỊA CHÍNH</h1>

              <div className="w-full mb-4 text-sm leading-6" style={{color:'#000'}}>
                   <p><strong>1. Thửa đất số:</strong> {getAttribute(formData, ['sothututhu', 'so_thua', 'sothua', 'shthua', 'st', 'sh_thua', 'thua', 'thua_dat', 'so_thu_tu_thua']) || '...'} 
                      <span className="ml-12"><strong>Tờ bản đồ số:</strong> {getAttribute(formData, ['sohieutoba', 'so_to', 'sodoto', 'shmap', 't', 'sh_to', 'shb', 'to_ban_do', 'tobando', 'so_hieu_to_ban_do']) || '...'}</span>
                   </p>
                   <p><strong>2. Địa chỉ thửa đất:</strong> {getAttribute(formData, ['dia_chi', 'diachi', 'address', 'dc', 'khu_vuc', 'vi_tri', 'dia_chi_thua_dat']) || '...'}</p>
                   <p><strong>3. Diện tích:</strong> {getAttribute(formData, ['dientich', 'dien_tich', 'shape_area', 'area', 'dt', 'poly_area', 'st_area(shape)', 'st_area(geometry)', 'dien_tich_phap_ly']) || '...'} m²</p>
                   <p><strong>4. Mục đích sử dụng:</strong> {getAttribute(formData, ['landType', 'loai_dat', 'kh', 'muc_dich', 'mdsd', 'ma_loai_dat']) === 'Residential' ? 'Đất ở' : (getAttribute(formData, ['landType', 'loai_dat', 'kh', 'muc_dich', 'mdsd']) || 'Đất nông nghiệp')}</p>
                   <p><strong>5. Tên người sử dụng đất:</strong> <span className="uppercase font-bold">{getAttribute(formData, ['ten_chu', 'tenchu', 'chu_so_huu', 'owner', 'name', 'ownerName', 'chusudung', 'ho_ten', 'chusd', 'ten', 'chu', 'name_vn', 'full_name', 'chu_su_dung']) || '...'}</span></p>
              </div>

              <div className="w-full flex flex-col items-center border border-black p-1 mb-2" style={{borderColor: '#000'}}>
                   <p className="w-full text-left font-bold mb-1 text-sm italic" style={{color:'#000'}}>6. Sơ đồ thửa đất:</p>
                   <canvas ref={parcelCanvasRef} width={600} height={350} className="w-full" />
              </div>

              <div className="w-full mb-4">
                   <p className="font-bold text-sm mb-1 italic" style={{color:'#000'}}>7. Bảng kê tọa độ và khoảng cách:</p>
                   <table className="w-full border-collapse text-sm text-center border border-black" style={{borderColor: '#000', color: '#000'}}>
                       <thead>
                           <tr style={{backgroundColor: '#e5e7eb'}}>
                               <th className="border border-black py-1 w-16 font-bold" style={{color: '#000', borderColor: '#000'}}>Hiệu đỉnh</th>
                               <th className="border border-black py-1 font-bold" style={{color: '#000', borderColor: '#000'}}>Tọa độ X (m)</th>
                               <th className="border border-black py-1 font-bold" style={{color: '#000', borderColor: '#000'}}>Tọa độ Y (m)</th>
                               <th className="border border-black py-1 font-bold" style={{color: '#000', borderColor: '#000'}}>Cạnh (m)</th>
                           </tr>
                       </thead>
                       <tbody>
                           {geometryPoints.map((p, i) => (
                               <tr key={i}>
                                   <td className="border border-black py-1 font-bold" style={{color: '#000', borderColor: '#000'}}>{p.id}</td>
                                   <td className="border border-black py-1" style={{color: '#000', borderColor: '#000'}}>{p.x.toFixed(2)}</td>
                                   <td className="border border-black py-1" style={{color: '#000', borderColor: '#000'}}>{p.y.toFixed(2)}</td>
                                   <td className="border border-black py-1 font-semibold" style={{color: '#000', borderColor: '#000'}}>{p.distanceNext ? p.distanceNext : '-'}</td>
                               </tr>
                           ))}
                       </tbody>
                   </table>
              </div>

              <div className="w-full flex justify-end mt-2" style={{color:'#000'}}>
                  <div className="text-center w-1/2">
                      <p className="italic">Tp. Hồ Chí Minh, ngày {new Date().getDate()} tháng {new Date().getMonth() + 1} năm {new Date().getFullYear()}</p>
                      <p className="font-bold uppercase mt-1">Người trích lục</p>
                      <div className="h-24"></div> 
                      <p className="italic text-xs mb-1">(Ký, ghi rõ họ tên)</p>
                      <p className="font-bold uppercase">{(user && user.name && user.name.trim() !== '') ? user.name : 'Thượng Hồng Thái'}</p>
                  </div>
              </div>
          </div>
      </div>

    </div>
  );
};

export default MapPage;

import React, { useEffect, useRef, useState } from 'react';
import { User, LandParcel, UserRole, WMSLayerConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { Layers, MousePointer2, Save, Trash2, X, AlertTriangle, CheckCircle, MapPin, Globe, Map as MapIcon, Eye, EyeOff, Info, List, FileText, WifiOff, RefreshCw, Search, Loader2, Printer, Navigation, Crosshair, ChevronDown, Table as TableIcon, User as UserIcon, Ruler, Tag, MousePointerClick, Filter, HelpCircle, Square, Database } from 'lucide-react';
import { jsPDF } from "jspdf";
import html2canvas from "html2canvas";
import proj4 from "proj4";

// OpenLayers uses global 'ol' from CDN
declare const ol: any;

// --- CẤU HÌNH HỆ TỌA ĐỘ VN-2000 ---
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.90441429,-39.30318279,-111.45032835,0.00928836,0.01975479,-0.00427372,0.252906278 +units=m +no_defs");

interface MapPageProps {
  user: User | null;
}

const MapPage: React.FC<MapPageProps> = ({ user }) => {
  const mapElement = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const popupElement = useRef<HTMLDivElement>(null);
  const popupOverlay = useRef<any>(null);

  // Layer Refs
  const osmLayer = useRef<any>(null);
  const googleLayer = useRef<any>(null);
  const vietbandoLayer = useRef<any>(null);
  const wmsLayerGroup = useRef<any>(null);
  const vectorLayer = useRef<any>(null); // For local parcels
  const highlightLayer = useRef<any>(null); // For selection highlight

  // Measure Refs
  const drawSource = useRef<any>(new ol.source.Vector());
  const drawLayer = useRef<any>(null);
  const drawInteraction = useRef<any>(null);
  const measureTooltips = useRef<any[]>([]); // Store active tooltips to clear later

  // State
  const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState<any>({});

  // Search State
  const [spatialTables, setSpatialTables] = useState<any[]>([]); // Danh sách xã/phường objects
  const [searchForm, setSearchForm] = useState({
      table: 'ALL',
      soTo: '',
      soThua: '',
      owner: ''
  });
  const [searchResults, setSearchResults] = useState<LandParcel[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);

  // Layer Control State
  const [activeBaseLayer, setActiveBaseLayer] = useState<'OSM' | 'GOOGLE' | 'VIETBANDO'>('OSM');
  const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
  const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
  const [activeLayerId, setActiveLayerId] = useState<string | null>(null); // NEW: Layer được chọn để truy vấn
  const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);

  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const [isFetchingInfo, setIsFetchingInfo] = useState(false);
  const [fetchError, setFetchError] = useState<string | null>(null);

  // Coordinate & Measure State
  const [mouseCoords, setMouseCoords] = useState<{lon: string, lat: string} | null>(null);
  const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);

  // Print Template Refs
  const printTemplateRef = useRef<HTMLDivElement>(null);
  const parcelCanvasRef = useRef<HTMLCanvasElement>(null);
  const [geometryPoints, setGeometryPoints] = useState<any[]>([]);

  // 1. Initial Load of Layers Config & Spatial Tables
  useEffect(() => {
      const initData = async () => {
          try {
              // Load WMS Layers
              const layers = await gisService.getLayers();
              setAvailableLayers(layers);
              const defaults = layers.filter(l => l.visible).map(l => l.id);
              setVisibleLayerIds(defaults);
              if (layers.length > 0) setActiveLayerId(layers[0].id);

              // Load Spatial Tables (Phường/Xã) for Search
              const tables = await gisService.getSpatialTables();
              setSpatialTables(tables);
          } catch (e) { console.error("Failed to load initial data", e); }
      };
      initData();
  }, []);

  // 2. Initialize OpenLayers Map
  useEffect(() => {
      if (!mapElement.current || mapInstance.current) return;
      if (typeof ol === 'undefined') {
          console.error("OpenLayers not loaded!"); 
          return;
      }

      // --- Base Layers ---
      osmLayer.current = new ol.layer.Tile({
          source: new ol.source.OSM(),
          visible: true,
          properties: { id: 'OSM' }
      });

      googleLayer.current = new ol.layer.Tile({
          source: new ol.source.XYZ({
              url: 'https://mt1.google.com/vt/lyrs=y&x={x}&y={y}&z={z}',
              attributions: '© Google Maps'
          }),
          visible: false,
          properties: { id: 'GOOGLE' }
      });

      vietbandoLayer.current = new ol.layer.Tile({
           source: new ol.source.XYZ({
              url: `${API_URL}/api/proxy/vietbando?z={z}&x={x}&y={y}`
           }),
           visible: false,
           properties: { id: 'VIETBANDO' }
      });

      // --- WMS Group (Empty initially) ---
      wmsLayerGroup.current = new ol.layer.Group({
          layers: [],
          zIndex: 10
      });

      // --- Vector Layer (Local Data) ---
      vectorLayer.current = new ol.layer.Vector({
          source: new ol.source.Vector(),
          style: new ol.style.Style({
              stroke: null, 
              fill: null 
          }),
          visible: false, 
          zIndex: 20
      });

      // --- Measure Layer ---
      drawLayer.current = new ol.layer.Vector({
          source: drawSource.current,
          style: new ol.style.Style({
              fill: new ol.style.Fill({ color: 'rgba(255, 255, 255, 0.2)' }),
              stroke: new ol.style.Stroke({ color: '#ffcc33', width: 2 }),
              image: new ol.style.Circle({
                  radius: 7,
                  fill: new ol.style.Fill({ color: '#ffcc33' })
              })
          }),
          zIndex: 101
      });

      // --- Highlight Layer (CHỈ HIỆN KHI CHỌN) ---
      highlightLayer.current = new ol.layer.Vector({
          source: new ol.source.Vector(),
          style: new ol.style.Style({
              stroke: new ol.style.Stroke({ color: '#ef4444', width: 3 }), 
              fill: new ol.style.Fill({ color: 'rgba(239, 68, 68, 0.1)' }), // Light red fill
              image: new ol.style.Circle({
                  radius: 6,
                  fill: new ol.style.Fill({ color: '#ef4444' }),
                  stroke: new ol.style.Stroke({ color: '#fff', width: 2 })
              })
          }),
          zIndex: 100
      });

      // --- Create Map ---
      const map = new ol.Map({
          target: mapElement.current,
          layers: [
              osmLayer.current, 
              googleLayer.current, 
              vietbandoLayer.current,
              wmsLayerGroup.current,
              drawLayer.current,
              highlightLayer.current
          ],
          view: new ol.View({
              center: ol.proj.fromLonLat([106.619, 11.284]), 
              zoom: 13
          }),
          controls: ol.control.defaults.defaults({
              zoom: true,
              rotate: false,
              attribution: false
          })
      });

      // --- Popup Overlay ---
      popupOverlay.current = new ol.Overlay({
          element: popupElement.current,
          autoPan: {
            animation: { duration: 250 }
          },
          positioning: 'bottom-center',
          offset: [0, -10]
      });
      map.addOverlay(popupOverlay.current);

      // --- Mouse Move Handler (Coordinates) ---
      map.on('pointermove', (evt: any) => {
          if (evt.dragging) return;
          const coords = ol.proj.toLonLat(evt.coordinate);
          setMouseCoords({
              lon: coords[0].toFixed(6),
              lat: coords[1].toFixed(6)
          });
      });

      // --- Click Handler (Priority: Vector Highlight -> WMS GetFeatureInfo) ---
      map.on('singleclick', async (evt: any) => {
          // If measuring, don't trigger info popup
          if (drawInteraction.current) return;

          setFetchError(null);

          // 1. Check if clicked on a HIGHLIGHTED feature (Result from Search)
          const pixel = map.getEventPixel(evt.originalEvent);
          const hitFeature = map.forEachFeatureAtPixel(pixel, (feature: any, layer: any) => {
              // Only consider features from highlightLayer or vectorLayer
              if (layer === highlightLayer.current || layer === vectorLayer.current) {
                  return feature;
              }
              return null;
          });

          if (hitFeature) {
              // == USE LOCAL DATA (From Search Result) ==
              const props = hitFeature.getProperties();
              // Construct a parcel object compatible with our viewer
              const mappedParcel: LandParcel = {
                  id: hitFeature.getId() || `local-${Date.now()}`,
                  geometry: props.geometry, // Or leave empty if handled by feature render
                  properties: {
                      ...props,
                      // Ensure standardization
                      ownerName: props.ownerName || props.tenchu || 'Chưa cập nhật',
                      landType: props.landType || props.loaidat || 'CLN',
                      area: props.area || props.dientich || 0,
                      address: props.address || props.diachi || '',
                      so_to: props.so_to || props.sodoto || '',
                      so_thua: props.so_thua || props.sothua || '',
                      // Preserve source info
                      tableName: props.tableName,
                      tableDisplayName: props.tableDisplayName
                  }
              };

              handleSelectParcel(mappedParcel);
              popupOverlay.current.setPosition(evt.coordinate);
              return; // Stop here, do not call WMS
          }

          // 2. If no vector hit, try WMS GetFeatureInfo

          // Lấy danh sách layers
          const layers = wmsLayerGroup.current.getLayers().getArray();
          let targetLayer: any = null;

          // Tìm lớp được đánh dấu là Active
          for (const l of layers) {
              if (l.get('isActive') === true && l.getVisible()) {
                  targetLayer = l;
                  break;
              }
          }

          // Fallback: Nếu không có lớp nào active, lấy lớp trên cùng đang hiện
          if (!targetLayer) {
               for (let i = layers.length - 1; i >= 0; i--) {
                    if (layers[i].getVisible()) {
                        targetLayer = layers[i];
                        break;
                    }
               }
          }

          if (!targetLayer) {
              setIsEditing(false);
              setSelectedParcel(null);
              popupOverlay.current.setPosition(undefined);
              highlightLayer.current.getSource().clear();
              return;
          }

          const targetSource = targetLayer.getSource();

          if (targetSource) {
               document.body.style.cursor = 'wait';
               highlightLayer.current.getSource().clear(); 
               setIsFetchingInfo(true);

               const view = map.getView();
               const viewResolution = view.getResolution();
               const viewProjection = view.getProjection();

               const url = targetSource.getFeatureInfoUrl(
                   evt.coordinate,
                   viewResolution,
                   viewProjection,
                   {
                       'INFO_FORMAT': 'application/json',
                       'FEATURE_COUNT': 1
                   }
               );

               if (url) {
                   const proxyUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(url)}`;

                   try {
                       const res = await fetch(proxyUrl);
                       if (!res.ok) throw new Error(`HTTP Error ${res.status}`);
                       const data = await res.json();

                       if (data.features && data.features.length > 0) {
                           const feature = data.features[0];
                           const props = feature.properties || {};

                           const getAttr = (keys: string[]) => {
                               for (const k of keys) {
                                   if (props[k] !== undefined && props[k] !== null) return props[k];
                                   const lower = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                                   if (lower) return props[lower];
                               }
                               return null;
                           };

                           const mappedParcel: LandParcel = {
                               id: feature.id || `wms-${Date.now()}`,
                               geometry: feature.geometry,
                               properties: {
                                    ownerName: getAttr(['tenchu', 'chu', 'owner', 'chusohuu', 'ten_chu']) || 'Chưa cập nhật',
                                    landType: getAttr(['loaidat', 'kyhieumucd', 'loai_dat', 'mdsd']) || 'Residential',
                                    area: Number(getAttr(['dientich', 'dien_tich', 'shape_area', 'area'])) || 0,
                                    pricePerM2: 0,
                                    totalValue: 0,
                                    planningStatus: 'Safe',
                                    branchId: 'WMS Data',
                                    updatedBy: 'GeoServer',
                                    so_to: getAttr(['sohieutoba', 'sodoto', 'shmap', 'so_to', 'map_sheet']),
                                    so_thua: getAttr(['sothututhu', 'sothua', 'shthua', 'so_thua', 'parcel_no']),
                                    address: getAttr(['diachi', 'dia_chi', 'address', 'khu_vuc']),
                                    tableDisplayName: targetLayer.get('config')?.name || 'Lớp WMS', // Use Layer name as source
                                    ...props 
                               }
                           };

                           if (feature.geometry) {
                               const reader = new ol.format.GeoJSON();
                               const olFeature = reader.readFeature(feature); 
                               highlightLayer.current.getSource().clear(); 
                               highlightLayer.current.getSource().addFeature(olFeature);
                           }

                           handleSelectParcel(mappedParcel);
                           popupOverlay.current.setPosition(evt.coordinate);

                       } else {
                           // Click vào chỗ trống (không có feature)
                           setIsEditing(false);
                           setSelectedParcel(null);
                           popupOverlay.current.setPosition(undefined);
                       }
                   } catch (err: any) {
                       console.warn("WMS Fetch Error:", err);
                   } finally {
                       setIsFetchingInfo(false);
                       document.body.style.cursor = 'default';
                   }
               } else {
                   setIsFetchingInfo(false);
                   document.body.style.cursor = 'default';
               }
          } else {
              document.body.style.cursor = 'default';
          }
      });

      mapInstance.current = map;

      return () => {
          map.setTarget(undefined);
          mapInstance.current = null;
      };
  }, []);

  // 3. Update Base Layers Visibility
  useEffect(() => {
      if (!mapInstance.current) return;
      osmLayer.current.setVisible(activeBaseLayer === 'OSM');
      googleLayer.current.setVisible(activeBaseLayer === 'GOOGLE');
      vietbandoLayer.current.setVisible(activeBaseLayer === 'VIETBANDO');
  }, [activeBaseLayer]);

  // 4. Update WMS Layers from Config & Handle Active State
  useEffect(() => {
      if (!mapInstance.current || !wmsLayerGroup.current) return;

      const currentLayers = wmsLayerGroup.current.getLayers().getArray();
      wmsLayerGroup.current.getLayers().clear();

      availableLayers.forEach(config => {
          const isActive = config.id === activeLayerId;
          const isVisible = visibleLayerIds.includes(config.id);

          if (isVisible) {
              const source = new ol.source.TileWMS({
                  url: config.url,
                  params: {
                      'LAYERS': config.layers,
                      'TILED': true,
                      'VERSION': '1.1.1',
                      'FORMAT': 'image/png',
                      'TRANSPARENT': true
                  },
                  serverType: 'geoserver',
                  transition: 0
              });

              const layer = new ol.layer.Tile({
                  source: source,
                  visible: true,
                  properties: { 
                      config: config,
                      isActive: isActive
                  },
                  zIndex: isActive ? 100 : 10
              });

              wmsLayerGroup.current.getLayers().push(layer);
          }
      });
  }, [availableLayers, visibleLayerIds, activeLayerId]);

  // 5. Draw PDF Canvas Logic (Depend on geometryPoints)
  useEffect(() => {
    if (geometryPoints.length === 0 || !parcelCanvasRef.current) return;

    const canvas = parcelCanvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear and set background
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const points = geometryPoints;

    // Calculate bounding box
    const xs = points.map(p => p.x);
    const ys = points.map(p => p.y);
    const minX = Math.min(...xs);
    const maxX = Math.max(...xs);
    const minY = Math.min(...ys);
    const maxY = Math.max(...ys);

    const width = maxX - minX;
    const height = maxY - minY;

    // Scale to fit canvas with padding
    const padding = 60; // Increased padding for labels
    const availWidth = canvas.width - padding * 2;
    const availHeight = canvas.height - padding * 2;

    const scaleX = width === 0 ? 1 : availWidth / width;
    const scaleY = height === 0 ? 1 : availHeight / height;
    const scale = Math.min(scaleX, scaleY);

    const toCanvasX = (mapX: number) => (mapX - minX) * scale + padding + (availWidth - width * scale)/2;
    const toCanvasY = (mapY: number) => canvas.height - ((mapY - minY) * scale + padding) - (availHeight - height * scale)/2;

    // 1. Draw Shape Outline
    ctx.beginPath();
    ctx.lineWidth = 2;
    ctx.strokeStyle = '#000000';

    points.forEach((p, i) => {
        const drawX = toCanvasX(p.x);
        const drawY = toCanvasY(p.y);

        if (i === 0) ctx.moveTo(drawX, drawY);
        else ctx.lineTo(drawX, drawY);
    });

    ctx.closePath();
    ctx.fillStyle = 'rgba(255, 255, 255, 0)'; // Transparent
    ctx.fill();
    ctx.stroke();

    // 2. Draw Edge Lengths (Along the line)
    ctx.font = "italic 11px Arial";
    ctx.fillStyle = "blue"; 
    ctx.textAlign = "center";
    ctx.textBaseline = "bottom";

    points.forEach((p, i) => {
        const nextIdx = (i + 1) % points.length; 

        const p1 = p;
        const p2 = points[nextIdx] || points[0];

        if (!p1.distanceNext) return;

        const x1 = toCanvasX(p1.x);
        const y1 = toCanvasY(p1.y);
        const x2 = toCanvasX(p2.x);
        const y2 = toCanvasY(p2.y);

        // Midpoint
        const midX = (x1 + x2) / 2;
        const midY = (y1 + y2) / 2;

        let angle = Math.atan2(y2 - y1, x2 - x1);

        if (angle > Math.PI / 2 || angle < -Math.PI / 2) {
            angle += Math.PI;
        }

        ctx.save();
        ctx.translate(midX, midY);
        ctx.rotate(angle);
        ctx.fillText(`${p1.distanceNext}m`, 0, -3); 
        ctx.restore();
    });

    // 3. Draw Points and Labels (Vertices)
    ctx.font = "bold 14px Times New Roman";
    ctx.fillStyle = "#000000"; 
    ctx.textAlign = "center";
    ctx.textBaseline = "bottom";

    points.forEach((p, i) => {
        const drawX = toCanvasX(p.x);
        const drawY = toCanvasY(p.y);

        ctx.beginPath();
        ctx.arc(drawX, drawY, 3, 0, 2 * Math.PI);
        ctx.fillStyle = "#000000"; 
        ctx.fill();

        ctx.fillText(String(p.id), drawX, drawY - 8);
    });
  }, [geometryPoints]);


  // --- Helper Functions ---

  const handleSelectParcel = (parcel: LandParcel) => {
      setSelectedParcel(parcel);
      setFormData(parcel.properties);
      setIsEditing(true);
      if (popupElement.current) {
          popupElement.current.style.display = 'block';
      }
  };

  const handleLocateMe = () => {
      setIsLocating(true);
      if (!navigator.geolocation) {
          alert("Không hỗ trợ GPS.");
          setIsLocating(false);
          return;
      }
      navigator.geolocation.getCurrentPosition((pos) => {
          const coords = [pos.coords.longitude, pos.coords.latitude];
          const view = mapInstance.current.getView();
          view.animate({
              center: ol.proj.fromLonLat(coords),
              zoom: 17,
              duration: 1000
          });

          const marker = new ol.Feature(new ol.geom.Point(ol.proj.fromLonLat(coords)));
          marker.setStyle(new ol.style.Style({
              image: new ol.style.Circle({
                  radius: 8,
                  fill: new ol.style.Fill({color: '#3b82f6'}),
                  stroke: new ol.style.Stroke({color: '#fff', width: 2})
              })
          }));
          highlightLayer.current.getSource().addFeature(marker);
          setIsLocating(false);
      }, () => {
          alert("Không thể lấy vị trí.");
          setIsLocating(false);
      });
  };

  // --- MEASURE LOGIC ---
  const formatLength = (line: any) => {
      const length = ol.sphere.getLength(line);
      let output;
      if (length > 100) {
          output = Math.round((length / 1000) * 100) / 100 + ' km';
      } else {
          output = Math.round(length * 100) / 100 + ' m';
      }
      return output;
  };

  const formatArea = (polygon: any) => {
      const area = ol.sphere.getArea(polygon);
      let output;
      if (area > 10000) {
          output = Math.round((area / 1000000) * 100) / 100 + ' km\xB2';
      } else {
          output = Math.round(area * 100) / 100 + ' m\xB2';
      }
      return output;
  };

  const createMeasureTooltip = () => {
      if (measureTooltips.current) {
          // Keep track of tooltips
      }
      const element = document.createElement('div');
      element.className = 'ol-tooltip ol-tooltip-measure bg-black/70 text-white px-2 py-1 rounded text-xs font-mono pointer-events-none whitespace-nowrap';
      const tooltip = new ol.Overlay({
          element: element,
          offset: [0, -15],
          positioning: 'bottom-center',
          stopEvent: false,
          insertFirst: false
      });
      mapInstance.current.addOverlay(tooltip);
      measureTooltips.current.push(tooltip);
      return { tooltip, element };
  };

  const addInteraction = (type: 'LineString' | 'Polygon') => {
      if (!mapInstance.current) return;

      const draw = new ol.interaction.Draw({
          source: drawSource.current,
          type: type,
          style: new ol.style.Style({
              fill: new ol.style.Fill({ color: 'rgba(255, 255, 255, 0.2)' }),
              stroke: new ol.style.Stroke({ color: 'rgba(0, 0, 0, 0.5)', lineDash: [10, 10], width: 2 }),
              image: new ol.style.Circle({
                  radius: 5,
                  stroke: new ol.style.Stroke({ color: 'rgba(0, 0, 0, 0.7)' }),
                  fill: new ol.style.Fill({ color: 'rgba(255, 255, 255, 0.2)' })
              })
          })
      });

      let listener: any;
      let measureTooltipElement: HTMLElement | null = null;
      let measureTooltip: any = null;

      draw.on('drawstart', (evt: any) => {
          const sketch = evt.feature;
          const tooltipData = createMeasureTooltip();
          measureTooltipElement = tooltipData.element;
          measureTooltip = tooltipData.tooltip;

          listener = sketch.getGeometry().on('change', (e: any) => {
              const geom = e.target;
              let output;
              let tooltipCoord;

              if (geom instanceof ol.geom.Polygon) {
                  output = formatArea(geom);
                  tooltipCoord = geom.getInteriorPoint().getCoordinates();
              } else if (geom instanceof ol.geom.LineString) {
                  output = formatLength(geom);
                  tooltipCoord = geom.getLastCoordinate();
              }

              if (measureTooltipElement) {
                  measureTooltipElement.innerHTML = output;
                  measureTooltip.setPosition(tooltipCoord);
              }
          });
      });

      draw.on('drawend', () => {
          measureTooltipElement!.className = 'ol-tooltip ol-tooltip-static bg-white border border-gray-400 text-black px-2 py-1 rounded text-xs font-bold shadow-sm';
          measureTooltip.setOffset([0, -7]);
          sketch = null;
          measureTooltipElement = null;
          ol.Observable.unByKey(listener);
      });

      let sketch: any = null;
      mapInstance.current.addInteraction(draw);
      drawInteraction.current = draw;
  };

  const handleMeasureChange = (type: 'LineString' | 'Polygon' | null) => {
      if (drawInteraction.current) {
          mapInstance.current.removeInteraction(drawInteraction.current);
          drawInteraction.current = null;
      }
      setMeasureMode(type);
      if (type) {
          addInteraction(type);
      }
  };

  const clearMeasurement = () => {
      drawSource.current.clear();
      measureTooltips.current.forEach(tooltip => mapInstance.current.removeOverlay(tooltip));
      measureTooltips.current = [];
      handleMeasureChange(null);
  };

  const handleSearch = async (e: React.FormEvent) => {
      e.preventDefault();
      // Validate: cần ít nhất 1 trường
      if (!searchForm.soTo && !searchForm.soThua && !searchForm.owner) {
          return;
      }

      setIsSearching(true);
      setSearchResults([]); 

      try {
          const { table, soTo, soThua, owner } = searchForm;

          const filters = { 
              sodoto: soTo.trim(),
              sothua: soThua.trim(),
              tenchu: owner.trim()
          };

          let allResults: LandParcel[] = [];

          // Nếu chọn "ALL" hoặc không chọn -> tìm hết
          if (table === 'ALL' || !table) {
              const tablesToSearch = spatialTables.length > 0 ? spatialTables.map((t: any) => t.table_name) : ['parcels'];

              // We need to keep the display names for the results
              const tableMap = new Map();
              spatialTables.forEach(t => tableMap.set(t.table_name, t.display_name));

              const searchPromises = tablesToSearch.map(t => 
                  gisService.searchParcels(t, filters)
                      .then(res => res.map(item => ({
                          ...item,
                          properties: { 
                              ...item.properties, 
                              tableName: t,
                              tableDisplayName: tableMap.get(t) || t // Add Display Name
                          } 
                      })))
                      .catch(() => [])
              );
              const resultsArray = await Promise.all(searchPromises);
              resultsArray.forEach(res => {
                  allResults = [...allResults, ...res];
              });
          } else {
              // Tìm đúng bảng đã chọn
              const res = await gisService.searchParcels(table, filters);
              const tableObj = spatialTables.find(t => t.table_name === table);
              const displayName = tableObj ? (tableObj.display_name || table) : table;

              allResults = res.map(item => ({
                  ...item,
                  properties: { 
                      ...item.properties, 
                      tableName: table,
                      tableDisplayName: displayName // Add Display Name
                  }
              }));
          }

          setSearchResults(allResults);
          if (allResults.length === 0) alert('Không tìm thấy kết quả nào.');
      } catch (err) { 
          console.error(err); 
          alert("Lỗi tìm kiếm: " + (err as Error).message);
      } finally { 
          setIsSearching(false); 
      }
  };

  const handleSelectSearchResult = (parcel: LandParcel) => {
      handleSelectParcel(parcel);
      const view = mapInstance.current.getView();
      if (parcel.geometry) {
           const format = new ol.format.GeoJSON();
           const feature = format.readFeature({
               type: "Feature", 
               geometry: parcel.geometry,
               properties: parcel.properties // IMPORTANT: Pass properties to OL Feature
           }, { featureProjection: 'EPSG:3857' });

           // Ensure ID is set
           feature.setId(parcel.id);

           const extent = feature.getGeometry().getExtent();
           view.fit(extent, { padding: [50,50,50,50], duration: 1000, maxZoom: 18 });

           highlightLayer.current.getSource().clear();
           highlightLayer.current.getSource().addFeature(feature);
           popupOverlay.current.setPosition(ol.extent.getCenter(extent));
      }
      setIsSearchOpen(false);
  };

  const toggleLayer = (layerId: string) => {
      setVisibleLayerIds(prev => {
          if (prev.includes(layerId)) {
              return prev.filter(id => id !== layerId);
          } else {
              return [...prev, layerId];
          }
      });
  };

  const handleSelectActiveLayer = (layerId: string) => {
      setActiveLayerId(layerId);
      if (!visibleLayerIds.includes(layerId)) {
          toggleLayer(layerId);
      }
  };

  const getAttribute = (obj: any, keys: string[]) => {
      if (!obj) return '';
      for (const k of keys) {
          if (obj[k] !== undefined && obj[k] !== null) return obj[k];
          const lowerKey = Object.keys(obj).find(pk => pk.toLowerCase() === k.toLowerCase());
          if (lowerKey) return obj[lowerKey];
      }
      return '';
  };

  const handleExportPDF = async () => {
      if (!selectedParcel || !selectedParcel.geometry) {
          alert("Vui lòng chọn một thửa đất để xuất trích lục.");
          return;
      }

      setIsGeneratingPDF(true);
      try {
          const format = new ol.format.GeoJSON();
          const feature = format.readFeature({
              type: "Feature",
              geometry: selectedParcel.geometry
          }); 
          const geom = feature.getGeometry().clone().transform('EPSG:3857', 'EPSG:4326');
          let coords: any[] = [];
          const type = geom.getType();

          if (type === 'MultiPolygon') {
               const polys = (geom as any).getCoordinates();
               if (polys.length > 0) coords = polys[0][0]; 
          } else if (type === 'Polygon') {
               const rings = (geom as any).getCoordinates();
               if (rings.length > 0) coords = rings[0];
          }

          if (!coords || coords.length === 0) throw new Error("Không thể đọc tọa độ hình học (Hỗ trợ Polygon/MultiPolygon)");

          const points: any[] = [];
          const loopLen = coords.length - 1;

          for (let i = 0; i < loopLen; i++) {
              const [lon, lat] = coords[i];
              const [x, y] = proj4('EPSG:4326', 'EPSG:9210', [lon, lat]);
              const [nextLon, nextLat] = coords[i + 1] || coords[0];
              const [nextX, nextY] = proj4('EPSG:4326', 'EPSG:9210', [nextLon, nextLat]);
              const dist = Math.sqrt(Math.pow(nextX - x, 2) + Math.pow(nextY - y, 2));

              points.push({
                  id: i + 1,
                  x, y,
                  distanceNext: dist.toFixed(2)
              });
          }
          setGeometryPoints(points);

          setTimeout(async () => {
              const element = printTemplateRef.current;
              if (element) {
                  const canvas = await html2canvas(element, { scale: 2, useCORS: true });
                  const imgData = canvas.toDataURL('image/png');
                  const imgWidth = canvas.width;
                  const imgHeight = canvas.height;
                  const a4WidthMm = 210;
                  const a4HeightMm = 297; 
                  const contentHeightMm = (imgHeight * a4WidthMm) / imgWidth;
                  const pdfHeightMm = contentHeightMm > a4HeightMm ? contentHeightMm : a4HeightMm;

                  const pdf = new jsPDF('p', 'mm', [a4WidthMm, pdfHeightMm]);
                  pdf.addImage(imgData, 'PNG', 0, 0, a4WidthMm, contentHeightMm);
                  pdf.save(`Trich_luc_thua_dat_${getAttribute(formData, ['sothua', 'so_thua'])}.pdf`);
              }
              setIsGeneratingPDF(false);
          }, 1000); 

      } catch (err: any) {
          console.error(err);
          alert("Lỗi xuất PDF: " + err.message);
          setIsGeneratingPDF(false);
      }
  };

  const canEdit = user && selectedParcel && selectedParcel.properties.branchId !== 'WMS Data' &&
                  (user.role === UserRole.ADMIN || (user.role === UserRole.EDITOR && selectedParcel.properties.branchId === user.branchId));

  return (
    <div className="relative w-full h-full bg-gray-100">
      {/* Map Container */}
      <div 
        ref={mapElement} 
