import React, { useEffect, useRef, useState } from 'react';
import { User, LandParcel, WMSLayerConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { Search, Layers, X, MapPin, Loader2 } from 'lucide-react';

// OpenLayers Imports
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import ImageLayer from 'ol/layer/Image';
import OSM from 'ol/source/OSM';
import ImageWMS from 'ol/source/ImageWMS';
import VectorLayer from 'ol/layer/Vector';
import VectorSource from 'ol/source/Vector';
import { Fill, Stroke, Style } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
import Overlay from 'ol/Overlay';
import { fromLonLat } from 'ol/proj';
import { getCenter } from 'ol/extent';
import Feature from 'ol/Feature';
import Geometry from 'ol/geom/Geometry';

import 'ol/ol.css';

interface MapPageProps {
  user: User | null;
}

const MapPage: React.FC<MapPageProps> = ({ user }) => {
  const mapElement = useRef<HTMLDivElement>(null);
  const popupRef = useRef<HTMLDivElement>(null);

  const mapInstance = useRef<Map | null>(null);
  const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);
  const popupOverlay = useRef<Overlay | null>(null);
  const wmsLayerInstances = useRef<Map<string, ImageLayer<ImageWMS>>>(new Map());

  const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchResults, setSearchResults] = useState<LandParcel[]>([]);
  const [searchQuery, setSearchQuery] = useState({ sothua: '', sodoto: '', tenchu: '', diachi: '' });

  const [wmsConfigs, setWmsConfigs] = useState<WMSLayerConfig[]>([]);
  const [isLayersPanelOpen, setIsLayersPanelOpen] = useState(false);
  const [loadingSearch, setLoadingSearch] = useState(false);

  // Initialize Map
  useEffect(() => {
    if (!mapElement.current || mapInstance.current) return;

    // Default Highlight Style
    const highlightStyle = new Style({
      stroke: new Stroke({
        color: '#f00',
        width: 3,
      }),
      fill: new Fill({
        color: 'rgba(255,0,0,0.1)',
      }),
    });

    // Highlight Layer
    const vectorSource = new VectorSource();
    highlightLayer.current = new VectorLayer({
      source: vectorSource,
      style: highlightStyle,
      zIndex: 999
    });

    // Popup Overlay
    if (popupRef.current) {
        popupOverlay.current = new Overlay({
            element: popupRef.current,
            autoPan: {
                animation: {
                    duration: 250,
                },
            },
        });
    }

    // Base Layer (OSM as default)
    const baseLayer = new TileLayer({
        source: new OSM(),
        visible: true
    });

    mapInstance.current = new Map({
      target: mapElement.current,
      layers: [baseLayer, highlightLayer.current],
      view: new View({
        center: fromLonLat([106.660172, 10.762622]), // Default Center (Ho Chi Minh City / Binh Duong region)
        zoom: 13,
      }),
      overlays: popupOverlay.current ? [popupOverlay.current] : []
    });

    // Initial Load Layers
    loadLayers();

    // Map Click Handler
    mapInstance.current.on('singleclick', () => {
        // Simple logic to clear selection if clicking outside
        // Note: Real WMS GetFeatureInfo would be implemented here
        if (highlightLayer.current?.getSource()?.getFeatures().length === 0) {
            setSelectedParcel(null);
            popupOverlay.current?.setPosition(undefined);
        }
    });

    return () => {
        if (mapInstance.current) {
            mapInstance.current.setTarget(undefined);
            mapInstance.current = null;
        }
    };
  }, []);

  const loadLayers = async () => {
      const layers = await gisService.getLayers();
      setWmsConfigs(layers);

      if (mapInstance.current) {
          layers.forEach(l => {
              if (l.visible && l.url && l.layers) {
                  addWMSLayer(l);
              }
          });
      }
  };

  const addWMSLayer = (config: WMSLayerConfig) => {
      if (!mapInstance.current) return;

      // Remove if exists
      if (wmsLayerInstances.current.has(config.id)) {
           const existing = wmsLayerInstances.current.get(config.id);
           if (existing) mapInstance.current.removeLayer(existing);
      }

      const source = new ImageWMS({
          url: config.url,
          params: { 'LAYERS': config.layers },
          ratio: 1,
          serverType: 'geoserver',
      });

      const layer = new ImageLayer({
          source: source,
          visible: config.visible,
          zIndex: 10
      });

      mapInstance.current.addLayer(layer);
      wmsLayerInstances.current.set(config.id, layer);
  };

  const toggleLayer = (config: WMSLayerConfig) => {
     const layer = wmsLayerInstances.current.get(config.id);
     if (layer) {
         layer.setVisible(!layer.getVisible());
         setWmsConfigs(prev => prev.map(c => c.id === config.id ? {...c, visible: !layer.getVisible()} : c));
     } else {
         // Re-add if missing
         if (config.visible === false) { // It was invisible, now visible
             const newConfig = {...config, visible: true};
             addWMSLayer(newConfig);
             setWmsConfigs(prev => prev.map(c => c.id === config.id ? newConfig : c));
         }
     }
  };

  const handleSearch = async () => {
      setLoadingSearch(true);
      try {
          // 'parcels' is the default table name usually
          const results = await gisService.searchParcels('parcels', searchQuery);
          setSearchResults(results);
      } catch (e) {
          console.error(e);
      } finally {
          setLoadingSearch(false);
      }
  };

  const handleSelectParcel = (parcel: LandParcel) => {
      setSelectedParcel(parcel);
  };

  const handleSelectSearchResult = (parcel: LandParcel) => {
      handleSelectParcel(parcel);
      if (!mapInstance.current || !highlightLayer.current || !popupOverlay.current) return;

      const view = mapInstance.current.getView();
      if (parcel.geometry) {
           const format = new GeoJSON();
           const feature = format.readFeature({
               type: "Feature", 
               geometry: parcel.geometry,
               properties: parcel.properties 
           }, { featureProjection: 'EPSG:3857' });

           feature.setId(parcel.id);

           const geom = feature.getGeometry();
           if (geom && typeof (geom as any).getExtent === 'function') {
               const extent = (geom as any).getExtent();
               view.fit(extent, { padding: [50,50,50,50], duration: 1000, maxZoom: 18 });

               highlightLayer.current.getSource()?.clear();
               highlightLayer.current.getSource()?.addFeature(feature as Feature<Geometry>);
               popupOverlay.current.setPosition(getCenter(extent));
           }
      }
      setIsSearchOpen(false);
  };

  return (
    <div className="relative w-full h-full bg-gray-900 overflow-hidden">
        {/* MAP CONTAINER */}
        <div ref={mapElement} className="w-full h-full" />

        {/* POPUP */}
        <div ref={popupRef} className="bg-white p-4 rounded shadow-lg min-w-[250px] relative hidden">
            {/* The hidden class above is removed by OpenLayers when overlay is active, or we handle visibility manually via OL */}
            <button onClick={() => { 
                popupOverlay.current?.setPosition(undefined); 
                setSelectedParcel(null);
                highlightLayer.current?.getSource()?.clear();
            }} className="absolute top-1 right-1 text-gray-500 hover:text-black">
                <X size={16} />
            </button>
            {selectedParcel ? (
                <div>
                    <h3 className="font-bold text-gray-800 border-b pb-1 mb-2">Thông tin Thửa đất</h3>
                    <div className="text-sm text-gray-600 space-y-1">
                        <p><strong>Số tờ:</strong> {selectedParcel.properties.so_to || selectedParcel.properties.sodoto}</p>
                        <p><strong>Số thửa:</strong> {selectedParcel.properties.so_thua || selectedParcel.properties.sothua}</p>
                        <p><strong>Chủ sở hữu:</strong> {selectedParcel.properties.ownerName || selectedParcel.properties.tenchu}</p>
                        <p><strong>Diện tích:</strong> {selectedParcel.properties.area || selectedParcel.properties.dientich} m²</p>
                        <p><strong>Loại đất:</strong> {selectedParcel.properties.landType}</p>
                        <p><strong>Địa chỉ:</strong> {selectedParcel.properties.address || selectedParcel.properties.diachi}</p>
                    </div>
                </div>
            ) : (
                <div className="text-sm text-gray-500">Chọn thửa đất để xem thông tin</div>
            )}
        </div>

        {/* CONTROLS */}
        <div className="absolute top-4 left-4 z-10 flex flex-col gap-2">
            <button 
                onClick={() => setIsSearchOpen(true)}
                className="bg-white text-gray-800 p-2 rounded shadow hover:bg-gray-100"
                title="Tìm kiếm"
            >
                <Search size={24} />
            </button>
            <button 
                onClick={() => setIsLayersPanelOpen(!isLayersPanelOpen)}
                className="bg-white text-gray-800 p-2 rounded shadow hover:bg-gray-100"
                title="Lớp bản đồ"
            >
                <Layers size={24} />
            </button>
        </div>

        {/* SEARCH PANEL */}
        {isSearchOpen && (
            <div className="absolute top-0 left-0 w-80 h-full bg-white shadow-xl z-20 flex flex-col animate-in slide-in-from-left duration-200">
                <div className="p-4 border-b flex justify-between items-center bg-blue-600 text-white">
                    <h2 className="font-bold flex items-center gap-2"><Search size={18} /> Tìm kiếm</h2>
                    <button onClick={() => setIsSearchOpen(false)}><X size={20} /></button>
                </div>

                <div className="p-4 space-y-3 bg-gray-50">
                    <div className="grid grid-cols-2 gap-2">
                         <input 
                            className="w-full border rounded p-2 text-sm text-gray-800"
                            placeholder="Số tờ..."
                            value={searchQuery.sodoto}
                            onChange={e => setSearchQuery({...searchQuery, sodoto: e.target.value})}
                        />
                        <input 
                            className="w-full border rounded p-2 text-sm text-gray-800"
                            placeholder="Số thửa..."
                            value={searchQuery.sothua}
                            onChange={e => setSearchQuery({...searchQuery, sothua: e.target.value})}
                        />
                    </div>
                    <input 
                        className="w-full border rounded p-2 text-sm text-gray-800"
                        placeholder="Tên chủ..."
                        value={searchQuery.tenchu}
                        onChange={e => setSearchQuery({...searchQuery, tenchu: e.target.value})}
                    />
                    <input 
                        className="w-full border rounded p-2 text-sm text-gray-800"
                        placeholder="Địa chỉ..."
                        value={searchQuery.diachi}
                        onChange={e => setSearchQuery({...searchQuery, diachi: e.target.value})}
                    />
                     <button 
                        onClick={handleSearch}
                        className="w-full bg-blue-600 text-white py-2 rounded font-bold hover:bg-blue-500 flex justify-center items-center gap-2"
                     >
                        {loadingSearch ? <Loader2 className="animate-spin" size={16} /> : 'Tìm kiếm'}
                     </button>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-2">
                    {searchResults.length === 0 && !loadingSearch && (
                        <p className="text-gray-500 text-sm text-center italic">Không tìm thấy kết quả</p>
                    )}
                    {searchResults.map((res, idx) => (
                        <div 
                            key={idx} 
                            onClick={() => handleSelectSearchResult(res)}
                            className="bg-white border rounded p-3 cursor-pointer hover:border-blue-500 hover:shadow transition-all group"
                        >
                            <div className="flex justify-between items-start">
                                <div className="font-bold text-gray-800">Tờ: {res.properties.so_to || res.properties.sodoto} - Thửa: {res.properties.so_thua || res.properties.sothua}</div>
                                <MapPin size={14} className="text-gray-400 group-hover:text-red-500" />
                            </div>
                            <div className="text-xs text-gray-600 font-medium">{res.properties.ownerName || res.properties.tenchu || 'Chưa có tên chủ'}</div>
                            <div className="text-xs text-gray-400 truncate mt-1">{res.properties.address || res.properties.diachi}</div>
                        </div>
                    ))}
                </div>
            </div>
        )}

        {/* LAYERS PANEL */}
        {isLayersPanelOpen && (
            <div className="absolute top-16 left-16 bg-white rounded shadow-xl p-4 z-20 w-64 animate-in fade-in zoom-in-95 duration-100">
                <h3 className="font-bold text-gray-800 mb-3 border-b pb-2 flex justify-between items-center">
                    Lớp bản đồ
                    <button onClick={() => setIsLayersPanelOpen(false)} className="text-gray-400 hover:text-black"><X size={14} /></button>
                </h3>
                <div className="space-y-2">
                     {wmsConfigs.length === 0 && <p className="text-gray-500 text-sm">Chưa có lớp bản đồ nào.</p>}
                     {wmsConfigs.map(layer => (
                         <div key={layer.id} className="flex items-center gap-2">
                             <input 
                                type="checkbox" 
                                checked={layer.visible}
                                onChange={() => toggleLayer(layer)}
                                className="w-4 h-4 text-blue-600 rounded cursor-pointer"
                             />
                             <span className="text-sm text-gray-700">{layer.name}</span>
                         </div>
                     ))}
                </div>
            </div>
        )}
    </div>
  );
};

export default MapPage;

