import TileWMS from 'ol/source/TileWMS';
import VectorLayer from 'ol/layer/Vector';
import VectorSource from 'ol/source/Vector';
import { Circle as CircleStyle, Fill, Stroke, Style } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
import Overlay from 'ol/Overlay';
import { fromLonLat } from 'ol/proj';
import { getCenter } from 'ol/extent';
import { User, LandParcel, WMSLayerConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { Search, Layers, X, Info, MapPin, Loader2 } from 'lucide-react';

interface MapPageProps {
  user: User | null;
}

const MapPage: React.FC<MapPageProps> = ({ user }) => {
  const mapElement = useRef<HTMLDivElement>(null);
  const popupElement = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);
  const popupOverlay = useRef<Overlay | null>(null);

  const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
  const [wmsLayers, setWmsLayers] = useState<WMSLayerConfig[]>([]);
  const [activeLayers, setActiveLayers] = useState<string[]>([]);

  // Search state
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<LandParcel[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [activeTab, setActiveTab] = useState<'info' | 'layers' | 'search'>('search');

  // Initialize Map
  useEffect(() => {
    if (!mapElement.current || mapInstance.current) return;

    // Base Layer
    const osmLayer = new TileLayer({
      source: new OSM(),
      properties: { name: 'OpenStreetMap' }
    });

    // Highlight Layer
    const vectorSource = new VectorSource();
    const vectorLayer = new VectorLayer({
      source: vectorSource,
      style: new Style({
        stroke: new Stroke({
          color: '#f00',
          width: 3,
        }),
        fill: new Fill({
          color: 'rgba(255, 0, 0, 0.1)',
        }),
      }),
      zIndex: 999
    });
    highlightLayer.current = vectorLayer;

    // Popup
    const overlay = new Overlay({
      element: popupElement.current || undefined,
      autoPan: {
        animation: {
          duration: 250,
        },
      },
      positioning: 'bottom-center',
      stopEvent: false,
      offset: [0, -10],
    });
