            <div className="flex items-center justify-between p-4 border-b border-gray-700">
                <h3 className="text-white font-bold">WebGIS Explorer</h3>
                <button onClick={() => setIsSearchOpen(false)} className="text-gray-400 hover:text-white"><X size={20} /></button>
            </div>

            {/* Tabs */}
            <div className="flex border-b border-gray-700">
                <button onClick={() => setActiveTab('search')} className={`flex-1 py-3 text-sm font-medium ${activeTab === 'search' ? 'text-blue-400 border-b-2 border-blue-400' : 'text-gray-400 hover:text-white'}`}>
                    <Search className="mx-auto mb-1" size={18} /> Tìm kiếm
                </button>
                <button onClick={() => setActiveTab('layers')} className={`flex-1 py-3 text-sm font-medium ${activeTab === 'layers' ? 'text-blue-400 border-b-2 border-blue-400' : 'text-gray-400 hover:text-white'}`}>
                    <Layers className="mx-auto mb-1" size={18} /> Lớp bản đồ
                </button>
                <button onClick={() => setActiveTab('info')} className={`flex-1 py-3 text-sm font-medium ${activeTab === 'info' ? 'text-blue-400 border-b-2 border-blue-400' : 'text-gray-400 hover:text-white'}`}>
                    <Info className="mx-auto mb-1" size={18} /> Chi tiết
                </button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
                {activeTab === 'search' && (
                    <div className="space-y-4">
                        <form onSubmit={handleSearch} className="relative">
                            <input 
                                type="text" 
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                placeholder="Nhập Số tờ Số thửa hoặc Tên..." 
                                className="w-full bg-gray-900 border border-gray-600 rounded p-2.5 pl-9 text-white focus:border-blue-500 outline-none text-sm"
                            />
                            <Search className="absolute left-3 top-2.5 text-gray-500" size={16} />
                            <button type="submit" className="hidden">Search</button>
                        </form>

                        {isSearching && <div className="text-center py-4 text-blue-400 flex justify-center"><Loader2 className="animate-spin" /></div>}

                        {!isSearching && searchResults.length > 0 && (
                            <div className="space-y-2">
                                <p className="text-xs text-gray-500 uppercase font-bold">Kết quả tìm kiếm ({searchResults.length})</p>
                                {searchResults.map((res) => (
                                    <div key={res.id} onClick={() => handleSelectSearchResult(res)} className="bg-gray-700/50 p-3 rounded cursor-pointer hover:bg-gray-700 border border-transparent hover:border-blue-500/50 transition-all">
                                        <div className="font-bold text-white text-sm">{res.properties.ownerName || 'Chưa xác định'}</div>
                                        <div className="text-xs text-gray-400 mt-1 flex gap-2">
                                            <span>Tờ: {res.properties.sodoto}</span>
                                            <span>Thửa: {res.properties.sothua}</span>
                                        </div>
                                        <div className="text-xs text-gray-500 mt-1 truncate">{res.properties.diachi}</div>
                                    </div>
                                ))}
                            </div>
                        )}
                         {!isSearching && searchResults.length === 0 && searchQuery && (
                            <div className="text-center py-8 text-gray-500 text-sm">Không tìm thấy kết quả nào.</div>
                        )}
                    </div>
                )}

                {activeTab === 'layers' && (
                    <div className="space-y-3">
                         <p className="text-xs text-gray-500 uppercase font-bold mb-2">Lớp bản đồ nền (Basemap)</p>
                         <div className="bg-gray-700/50 p-3 rounded flex items-center justify-between border border-blue-500/50">
                             <span className="text-sm text-white">OpenStreetMap</span>
                             <div className="w-3 h-3 bg-green-500 rounded-full shadow-[0_0_5px_rgba(34,197,94,0.8)]"></div>
                         </div>

                         <div className="h-px bg-gray-700 my-4"></div>

                         <p className="text-xs text-gray-500 uppercase font-bold mb-2">Lớp dữ liệu chuyên đề</p>
                         {wmsLayers.length === 0 && <div className="text-gray-500 text-sm italic">Chưa có lớp bản đồ nào được cấu hình.</div>}
                         {wmsLayers.map(l => (
                             <div key={l.id} className="flex items-center justify-between bg-gray-900/50 p-3 rounded border border-gray-700">
                                 <span className="text-sm text-gray-200">{l.name}</span>
                                 <button 
                                    onClick={() => toggleLayer(l)}
                                    className={`w-10 h-5 rounded-full relative transition-colors ${activeLayers.includes(l.id) ? 'bg-blue-600' : 'bg-gray-600'}`}
                                 >
                                     <span className={`absolute top-1 left-1 bg-white w-3 h-3 rounded-full transition-transform ${activeLayers.includes(l.id) ? 'translate-x-5' : 'translate-x-0'}`} />
                                 </button>
                             </div>
                         ))}
                    </div>
                )}

                {activeTab === 'info' && selectedParcel ? (
                    <div className="space-y-4">
                        <div className="bg-blue-900/20 p-4 rounded border border-blue-800">
                            <h4 className="text-lg font-bold text-blue-400 mb-1">{selectedParcel.properties.ownerName}</h4>
                            <p className="text-sm text-gray-300">{selectedParcel.properties.address}</p>
                        </div>

                        <div className="space-y-3">
                            <div className="grid grid-cols-2 gap-3">
                                <div className="bg-gray-700/30 p-3 rounded">
                                    <div className="text-xs text-gray-500 uppercase">Số tờ</div>
                                    <div className="font-mono text-lg font-bold text-white">{selectedParcel.properties.so_to || selectedParcel.properties.sodoto}</div>
                                </div>
                                <div className="bg-gray-700/30 p-3 rounded">
                                    <div className="text-xs text-gray-500 uppercase">Số thửa</div>
                                    <div className="font-mono text-lg font-bold text-white">{selectedParcel.properties.so_thua || selectedParcel.properties.sothua}</div>
                                </div>
                            </div>

                            <div className="bg-gray-700/30 p-3 rounded flex justify-between items-center">
                                <span className="text-sm text-gray-400">Diện tích</span>
                                <span className="font-mono font-bold text-white">{Number(selectedParcel.properties.area).toLocaleString()} m²</span>
                            </div>

                            <div className="bg-gray-700/30 p-3 rounded flex justify-between items-center">
                                <span className="text-sm text-gray-400">Loại đất</span>
                                <span className="font-bold text-yellow-400">{selectedParcel.properties.landType}</span>
                            </div>

                             <div className="bg-gray-700/30 p-3 rounded">
                                <div className="text-xs text-gray-500 uppercase mb-1">Dữ liệu thô (JSON)</div>
                                <pre className="text-[10px] text-gray-400 overflow-auto max-h-40 custom-scrollbar bg-black/20 p-2 rounded">
                                    {JSON.stringify(selectedParcel.properties, null, 2)}
                                </pre>
                            </div>
                        </div>
                    </div>
                ) : activeTab === 'info' && (
                    <div className="text-center py-10 text-gray-500 text-sm">
                        <MapPin size={32} className="mx-auto mb-2 opacity-50" />
                        Chọn một thửa đất trên bản đồ hoặc tìm kiếm để xem thông tin chi tiết.
                    </div>
                )}
            </div>
      </div>

      {/* Floating Toggle Button */}
      {!isSearchOpen && (
          <button 
            onClick={() => setIsSearchOpen(true)}
            className="absolute top-4 right-4 z-10 bg-blue-600 hover:bg-blue-500 text-white p-3 rounded-full shadow-lg transition-transform hover:scale-105"
          >
              <Search size={20} />
          </button>
      )}
    </div>
  );
};

export default MapPage;
